    #[test]
    fn confirm_auto_review_refuses_when_remote_session_live() {
        // confirm_auto_review must push a warning toast and keep the prompt
        // up rather than launch a new session over the live one.
        let running_work = make_assignment_typed("running", 10, "repo-a", Some("work"));
        let running_aid = running_work.id.clone();
        let mut app = make_app_with_assignments(vec![running_work]);
        app.live_tmux_sessions.push(make_live_tmux_session(&running_aid, 10, "repo-a"));
        app.pending_auto_review = Some(mk_pending_auto_review("repo-a", 10));
        app.confirm_auto_review();
        // Prompt must still be set (not dismissed).
        assert!(app.pending_auto_review.is_some(), "pending_auto_review must stay set");
        // A warning toast must have been pushed.
        assert!(
            app.toasts.iter().any(|t| t.0.body.contains("live session")),
            "expected a 'live session' warning toast, got: {:?}",
            app.toasts.iter().map(|t| &t.0.body).collect::<Vec<_>>(),
        );
    }

    #[test]
    fn confirm_merge_refuses_when_remote_session_live() {
        // confirm_merge must toast and keep the pending merge prompt, not
        // launch a merge agent over the live session.
        let running_work = make_assignment_typed("running", 10, "repo-a", Some("work"));
        let running_aid = running_work.id.clone();
        let mut app = make_app_with_assignments(vec![running_work]);
        app.live_tmux_sessions.push(make_live_tmux_session(&running_aid, 10, "repo-a"));
        app.pending_merge = Some(PendingMerge {
            coord_repo: "repo-a".to_string(),
            repo_slug: "repo-a".to_string(),
            issue_num: 10,
        });
        app.confirm_merge();
        assert!(app.pending_merge.is_some(), "pending_merge must stay set");
        // The guard message uses "interactive session" (shared with the
        // embedded-pane branch); just verify a relevant toast was pushed.
        assert!(
            app.toasts.iter().any(|t| t.0.body.contains("interactive session") || t.0.body.contains("#10")),
            "expected a session-blocking warning toast, got: {:?}",
            app.toasts.iter().map(|t| &t.0.body).collect::<Vec<_>>(),
        );
    }

    #[test]
    fn build_prompt_dialog_shows_reattach_when_auto_review_blocked_by_live_session() {
        // When pending_auto_review is set but a live session is present,
        // build_prompt_dialog must substitute the "Reattach to live session"
        // dialog rather than the normal "Start review" dialog.
        let running_work = make_assignment_typed("running", 10, "repo-a", Some("work"));
        let running_aid = running_work.id.clone();
        let mut app = make_app_with_assignments(vec![running_work]);
        app.live_tmux_sessions.push(make_live_tmux_session(&running_aid, 10, "repo-a"));
        app.pending_auto_review = Some(mk_pending_auto_review("repo-a", 10));
        let dialog = app.build_prompt_dialog().expect("dialog must be present");
        // Must NOT be the normal "Start review" dialog.
        assert_ne!(
            dialog.id,
            WidgetId::new("dialog:auto-review"),
            "normal 'Start review' dialog must be suppressed",
        );
        // Must be the live-session-blocking dialog.
        assert_eq!(dialog.id, WidgetId::new("dialog:reattach-first"));
        // Body must mention "Reattach to live session".
        let body_text: String = dialog
            .body
            .iter()
            .flat_map(|b| b.spans.iter())
            .map(|s| s.text.as_str())
            .collect::<Vec<_>>()
            .join(" ");
        assert!(
            body_text.contains("Reattach to live session"),
            "dialog body must contain 'Reattach to live session', got: {body_text}",
        );
    }

    // ── #722 Esc-dismiss path: pending offer must survive while blocking ──────

    /// Pressing Esc while the live-session blocking dialog is showing must NOT
    /// destroy the pending review offer.  The operator will reattach and `/exit`
    /// the session; the detector re-fires automatically once clear.
    ///
    /// This tests the key-handler path (lines ~26722 ff.) via the full
    /// `ShellAdapter → handle → render` pipeline using `TuiDriver`.
    #[test]
    fn esc_while_blocking_dialog_preserves_pending_auto_review() {
        use quadraui::tui::testing::driver_with_shell;

        let running_work = make_assignment_typed("running", 10, "repo-a", Some("work"));
        let running_aid = running_work.id.clone();
        let mut app = make_app_with_assignments(vec![running_work]);
        app.live_tmux_sessions.push(make_live_tmux_session(&running_aid, 10, "repo-a"));
        app.pending_auto_review = Some(mk_pending_auto_review("repo-a", 10));

        let mut driver = driver_with_shell(app, CoordApp::shell_config(), 120, 40);

        // Initial screen: blocking dialog must be showing.
        assert!(
            driver.screen_contains("Reattach to live session"),
            "initial screen must show blocking dialog:\n{}",
            driver.screen(),
        );

        // Press Esc — must NOT destroy the pending offer.
        driver.press_named(quadraui::NamedKey::Escape);

        // Blocking dialog must still be showing (pending preserved).
        assert!(
            driver.screen_contains("Reattach to live session"),
            "blocking dialog must survive Esc — pending offer must be preserved:\n{}",
            driver.screen(),
        );
        // Normal "Start review" action must still be suppressed.
        assert!(
            !driver.screen_contains("Start review"),
            "normal review offer must still be suppressed after Esc:\n{}",
            driver.screen(),
        );
    }

    /// `dismiss_prompt_dialog` (outside-click path) must preserve
    /// `pending_auto_review` when the live-session blocking dialog is active.
    #[test]
    fn dismiss_prompt_dialog_preserves_auto_review_when_blocking() {
        let running_work = make_assignment_typed("running", 10, "repo-a", Some("work"));
        let running_aid = running_work.id.clone();
        let mut app = make_app_with_assignments(vec![running_work]);
        app.live_tmux_sessions.push(make_live_tmux_session(&running_aid, 10, "repo-a"));
        app.pending_auto_review = Some(mk_pending_auto_review("repo-a", 10));
        // Simulate outside-click dismiss (the path that calls dismiss_prompt_dialog).
        app.dismiss_prompt_dialog();
        assert!(
            app.pending_auto_review.is_some(),
            "pending_auto_review must survive dismiss_prompt_dialog when blocking dialog active",
        );
    }

    /// `fire_dialog_button("close", …)` (the blocking dialog's dismiss button)
    /// must preserve `pending_auto_review`, NOT clear it.
    ///
    /// Tested by driving the full TuiDriver render + click path: the "Dismiss"
    /// button is located on screen and clicked; the blocking dialog must still
    /// be present after the click (pending offer preserved).
    #[test]
    fn fire_dialog_button_close_preserves_auto_review_when_blocking() {
        use quadraui::tui::testing::driver_with_shell;

        let running_work = make_assignment_typed("running", 10, "repo-a", Some("work"));
        let running_aid = running_work.id.clone();
        let mut app = make_app_with_assignments(vec![running_work]);
        app.live_tmux_sessions.push(make_live_tmux_session(&running_aid, 10, "repo-a"));
        app.pending_auto_review = Some(mk_pending_auto_review("repo-a", 10));

        // Drive through the full pipeline: render the blocking dialog so
        // dialog_layout is populated, then click the dismiss button.
        let mut driver = driver_with_shell(app, CoordApp::shell_config(), 120, 40);

        // Confirm the blocking dialog is visible before clicking.
        assert!(
            driver.screen_contains("Reattach to live session"),
            "initial screen must show blocking dialog:\n{}",
            driver.screen(),
        );

        // Locate and click the dismiss button — try the full label first, then
        // "Dismiss" alone (renderer may collapse spaces or truncate label text).
        let pos = driver.find("Esc  Dismiss").or_else(|| driver.find("Dismiss"));
        if let Some((x, y)) = pos {
            driver.click(x, y);
            // The blocking dialog must still be showing after clicking dismiss.
            assert!(
                driver.screen_contains("Reattach to live session"),
                "blocking dialog must persist after clicking dismiss:\n{}",
                driver.screen(),
            );
        } else {
            // Button not found by text — render the dialog and click the
            // outside-click path (equivalent UX: outside-click must also
            // preserve the pending offer).  This path exercises
            // `dismiss_prompt_dialog` rather than `fire_dialog_button("close")`,
            // so it's a weaker but valid fallback.
            //
            // Click a cell that is clearly outside the dialog (top-left corner).
            driver.click(0.5, 0.5);
            assert!(
                driver.screen_contains("Reattach to live session"),
                "blocking dialog must persist after outside-click dismiss:\n{}",
                driver.screen(),
            );
        }
    }

    /// `issue_has_live_session_for_repo` must NOT match a live session on a
    /// different repo even when the issue number is the same.  This is the
    /// multi-repo false-positive guard introduced in #722.
    #[test]
    fn issue_has_live_session_for_repo_does_not_cross_repo_match() {
        let running_work = make_assignment_typed("running", 10, "repo-b", Some("work"));
        let running_aid = running_work.id.clone();
        let mut app = make_app_with_assignments(vec![running_work]);
        // Session is for repo-b/#10.
        app.live_tmux_sessions.push(make_live_tmux_session(&running_aid, 10, "repo-b"));

        // repo-specific lookup for repo-a/#10 must return false.
        assert!(
            !app.issue_has_live_session_for_repo(10, "repo-a"),
            "repo-a/#10 must not see a live session belonging to repo-b/#10",
        );
        // But repo-b/#10 must return true.
        assert!(
            app.issue_has_live_session_for_repo(10, "repo-b"),
            "repo-b/#10 must detect its own live session",
        );
    }

    #[test]
    fn request_changes_review_aid_for_picks_latest() {
        let mut older = review_of("id-10-done", 10, "repo-a", Some("request-changes"));
        older.id = "rev-old".to_string();
        older.dispatched_at = Some(2_000_000.0);
        let mut newer = review_of("id-10-fix", 10, "repo-a", Some("request-changes"));
        newer.id = "rev-new".to_string();
        newer.dispatched_at = Some(2_500_000.0);
        let app = make_app_with_assignments(vec![older, newer]);
        assert_eq!(
            app.request_changes_review_aid_for("repo-a", 10).as_deref(),
            Some("rev-new"),
        );
    }

    #[test]
    fn request_changes_review_aid_for_none_when_latest_review_approved() {
        // #602: a round-1 request-changes review that a LATER review APPROVED is
        // resolved — the resolver must return None so a subsequent test-failure
        // fix targets the failed WORK row (→ its synthesized test_reason brief),
        // not the stale reviewer findings.  This is the fail→fix misroute that
        // briefed the worker with a previous reviewer's already-fixed concerns.
        let mut rc = review_of("id-10-done", 10, "repo-a", Some("request-changes"));
        rc.id = "rev-rc".to_string();
        rc.dispatched_at = Some(2_000_000.0);
        let mut approved = review_of("id-10-fix", 10, "repo-a", Some("approve"));
        approved.id = "rev-ok".to_string();
        approved.dispatched_at = Some(2_500_000.0);
        let app = make_app_with_assignments(vec![rc, approved]);
        assert_eq!(
            app.request_changes_review_aid_for("repo-a", 10),
            None,
            "a later approval resolves the earlier request-changes",
        );
    }

    #[test]
    fn fix_gate_ignores_older_empty_review_when_latest_has_findings() {
        // #648: two request-changes reviews for the same issue — an OLDER one
        // with null findings (original capture missed) and a NEWER one carrying
        // full findings (recovered on re-review).  The fix-launch gate must key
        // on the LATEST review (the id `--fix-of` resolves), so it must NOT
        // demand manual findings entry — the old `.any(... is_none())` wrongly
        // tripped on the stale empty row and (on confirm) overwrote the good
        // findings via `coord set-review-findings`.
        let mut older = review_of("id-10-done", 10, "repo-a", Some("request-changes"));
        older.id = "rev-old".to_string();
        older.dispatched_at = Some(2_000_000.0);
        older.review_findings = None; // original capture missed
        let mut newer = review_of("id-10-done", 10, "repo-a", Some("request-changes"));
        newer.id = "rev-new".to_string();
        newer.dispatched_at = Some(2_500_000.0);
        newer.review_findings =
            Some(r#"{"verdict":"request-changes","body":"fix render_impl.rs:687"}"#.to_string());
        let app = make_app_with_assignments(vec![older, newer]);
        assert!(
            !app.fix_review_needs_findings_capture("repo-a", 10),
            "latest review has findings → no manual-entry gate despite the older empty review",
        );

        // Sanity: when the latest review itself lacks findings, the gate fires.
        let mut only_empty = review_of("id-11-done", 11, "repo-a", Some("request-changes"));
        only_empty.id = "rev-empty".to_string();
        only_empty.dispatched_at = Some(2_000_000.0);
        only_empty.review_findings = None;
        let app2 = make_app_with_assignments(vec![only_empty]);
        assert!(
            app2.fix_review_needs_findings_capture("repo-a", 11),
            "latest review without findings → manual-entry gate fires",
        );
    }

