    /// Extract the body text lines from a `Dialog`.
    fn dialog_body_text(dlg: &Dialog) -> Vec<String> {
        dlg.body
            .iter()
            .flat_map(|b| b.spans.iter())
            .map(|s| s.text.clone())
            .collect()
    }

