    #[test]
    fn failed_work_aid_with_branch_for_none_when_nothing_dispatched() {
        let app = make_test_app(BoardData::default());
        assert!(app.failed_work_aid_with_branch_for("api", 42).is_none());
    }

    #[test]
    fn failed_work_aid_with_branch_for_none_once_a_later_rework_succeeds() {
        // #1104: `--rework-of` continues the SAME branch as a NEW type="work"
        // row (`_dispatch_rework_of`). Once that rework lands `done`, it
        // becomes the latest work attempt and Continue must stop offering
        // the now-superseded original failure — "no subsequent successful
        // work/rework on that branch" per the issue's acceptance criteria.
        let mut app = make_test_app(BoardData::default());
        let mut failed = make_assignment_typed("failed", 42, "api", Some("work"));
        failed.id = "work-1".to_string();
        failed.branch = Some("issue-42-work".to_string());
        failed.dispatched_at = Some(100.0);
        let mut reworked = make_assignment_typed("done", 42, "api", Some("work"));
        reworked.id = "work-2".to_string();
        reworked.branch = Some("issue-42-work".to_string());
        reworked.dispatched_at = Some(200.0);
        app.data.assignments.push(failed);
        app.data.assignments.push(reworked);
        assert!(
            app.failed_work_aid_with_branch_for("api", 42).is_none(),
            "a later successful rework must retire the Continue offer for the earlier failure"
        );
    }

    #[test]
    fn failed_work_aid_with_branch_for_ignores_non_work_assignment_types() {
        // A failed REVIEW or SMOKE row must never be mistaken for a
        // continuable work attempt.
        let mut app = make_test_app(BoardData::default());
        let mut a = make_assignment_typed("failed", 42, "api", Some("review"));
        a.branch = Some("issue-42-work".to_string());
        app.data.assignments.push(a);
        assert!(app.failed_work_aid_with_branch_for("api", 42).is_none());
    }

    #[test]
    fn context_menu_shows_continue_only_when_latest_work_attempt_failed_with_branch() {
        // #1104: additive next to Work/Plan in Start (interactive) — Fix's
        // precedent, gated the same way.
        let mut app = make_test_app(BoardData::default());
        let mut a = make_assignment_typed("failed", 42, "api", Some("work"));
        a.branch = Some("issue-42-work".to_string());
        app.data.assignments.push(a);
        // `selected_failed_work_aid_with_branch` (like `selected_test_failed_
        // work_aid`, Fix's equivalent) reads the SELECTED Pipeline row —
        // `active_view` must be Pipeline (not the `Board` default) or
        // `selected_issue_repo_and_key` resolves via the Board selection
        // instead, not `pipeline_sel`. Keep this in sync with the
        // `issue_number`/`repo_name` params below, as the real right-click
        // handler does.
        app.active_view = SidebarView::Pipeline;
        app.pipeline_issues = vec![PipelineIssue {
            number: 42,
            title: "t".to_string(),
            body: String::new(),
            repo_slug: "acme/api".to_string(),
            coord_repo: Some("api".to_string()),
            matched_labels: vec!["coord".to_string()],
            all_labels: vec!["coord".to_string()],
            is_closed: false,
        }];
        app.pipeline_repo_names = vec!["api".to_string()];
        app.pipeline_sel = Some(0);
        let items = app.context_menu_items_for_pipeline_row(
            Some(42),
            &PipelineRowLifecycle::InProgress,
            Some("api"),
        );
        let start_interactive = items
            .iter()
            .find(|i| i.label == "Start (interactive)")
            .expect("Start (interactive) submenu must be present");
        assert!(
            start_interactive
                .submenu
                .as_ref()
                .expect("Start (interactive) must be a submenu parent")
                .iter()
                .any(|c| c.label == "Continue"),
            "Continue must be offered when the latest work attempt failed with a branch"
        );
    }

    #[test]
    fn context_menu_hides_continue_when_no_failed_branched_attempt() {
        let app = make_test_app(BoardData::default());
        let items = app.context_menu_items_for_pipeline_row(
            Some(42),
            &PipelineRowLifecycle::New,
            Some("api"),
        );
        let start_interactive = items
            .iter()
            .find(|i| i.label == "Start (interactive)")
            .expect("Start (interactive) submenu must be present");
        assert!(
            !start_interactive
                .submenu
                .as_ref()
                .expect("Start (interactive) must be a submenu parent")
                .iter()
                .any(|c| c.label == "Continue"),
            "Continue must NOT be offered with no failed-with-branch work attempt"
        );
    }

    // ── #1059 fix-2: Gate A dispatch-failure full-text modal ──────────────

    #[test]
    fn is_gate_a_mock_dispatch_label_matches_only_the_mock_command() {
        // The label `spawn_queued` records for a Gate A dispatch.
        assert!(is_gate_a_mock_dispatch_label(
            "coord acceptance mock claude-coordinator 1041"
        ));
        // Trailing-whitespace / no-arg edge (defensive).
        assert!(is_gate_a_mock_dispatch_label("coord acceptance mock"));
        // Sibling `acceptance` leaf verbs must NOT be captured — they are not
        // Gate A dispatches and get the normal command-failed toast.
        assert!(!is_gate_a_mock_dispatch_label(
            "coord acceptance run --issue 1041"
        ));
        assert!(!is_gate_a_mock_dispatch_label(
            "coord acceptance record --issue 1041 --sha abc"
        ));
        assert!(!is_gate_a_mock_dispatch_label("coord milestone dispatch api 42"));
    }

    #[test]
    fn gate_a_dispatch_failure_opens_full_text_error_dialog() {
        // #1059 fix-2: the exact failure the operator hit — "Dispatch Gate A
        // mock" against a repo with no acceptance driver — must surface the
        // COMPLETE reason in a dismissible modal, NOT a ~40-col-truncated
        // "Command failed" toast that reads as a permanent wedge.
        let mut app = make_app_default();
        let full_reason = "error: repo 'claude-coordinator' has no acceptance \
             driver configured — add it under acceptance.drivers in \
             coordinator.yml before running Gate A (docs/ORACLE_LOOP.md)";
        // Queue the failing result BEFORE spawning — `new_for_test`'s no_spawn
        // path resolves synchronously at spawn time.
        app.command_runner.push_canned_result(1, full_reason);
        app.command_runner
            .spawn_queued(&["acceptance", "mock", "claude-coordinator", "1041"]);
        let toasts_before = app.toasts.len();

        // Drain the (already-resolved) result through the poll handler.
        app.run_periodic_work();

        let body = app
            .gate_a_error_dialog
            .as_ref()
            .expect("a failed Gate A dispatch must raise the full-text modal");
        assert!(
            body.contains("no acceptance driver configured"),
            "the full reason must be preserved (not truncated), got: {body}"
        );
        // The generic "Command failed" toast must be suppressed for this case
        // (the modal is the single, complete notification).
        assert!(
            !app
                .toasts
                .iter()
                .skip(toasts_before)
                .any(|(t, _, _)| t.title == "Command failed"),
            "the truncating command-failed toast must be suppressed when the \
             full-text Gate A modal is shown"
        );
    }

    #[test]
    fn gate_a_error_dialog_renders_full_reason_and_dismisses() {
        // #1059 fix-2: the modal actually paints through the full
        // ShellAdapter → render path (word-wrapped, so a long reason is
        // readable), and Esc dismisses it.
        use quadraui::tui::testing::driver_with_shell;

        let mut app = make_app_default();
        app.gate_a_error_dialog = Some(
            "repo 'claude-coordinator' has no acceptance driver configured — \
             add it under acceptance.drivers in coordinator.yml"
                .to_string(),
        );

        // Structural: title + the full reason survive into the built dialog.
        let dlg = app
            .build_prompt_dialog()
            .expect("gate-a error dialog must build when set");
        let body = dialog_body_text(&dlg).join(" ");
        assert!(
            body.contains("no acceptance driver configured"),
            "dialog body must carry the full reason, got:\n{body}"
        );
        assert!(
            body.contains("Nothing was claimed"),
            "dialog must reassure the operator nothing was left in-flight, got:\n{body}"
        );

        let mut driver = driver_with_shell(app, CoordApp::shell_config(), 120, 40);
        assert!(
            driver.screen_contains("Gate A dispatch failed"),
            "modal title must render on screen:\n{}",
            driver.screen(),
        );
        // Esc dismisses the modal.
        driver.press(quadraui::Key::Named(quadraui::NamedKey::Escape));
        assert!(
            !driver.screen_contains("Gate A dispatch failed"),
            "Esc must dismiss the Gate A error modal:\n{}",
            driver.screen(),
        );
    }

    // ── #1060: per-issue acceptance actions (JIT author + record) ─────────

    /// Row 0 (#42) is a member of milestone tracking-issue #751's work order
    /// (via `milestone_work_orders`) and has an `open_issues` entry carrying
    /// milestone #9 (via `pipeline_issue_milestone`) — the acceptance menu
    /// items apply. Row 1 (#99) is an ordinary issue in the same repo with no
    /// work-order membership — the items must not appear.
    /// `repo_path` backs `pipeline_repo_paths["api"]`, used by
    /// `gate_a_contract_exists_for`'s on-disk contract.md check.
    fn make_pipeline_app_for_acceptance_menu_test(selected_idx: usize, repo_path: &str) -> CoordApp {
        let mut pipeline_repo_paths = std::collections::HashMap::new();
        pipeline_repo_paths.insert("api".to_string(), repo_path.to_string());
        let data = BoardData {
            pipeline_default_gates: vec!["review".to_string(), "merge".to_string()],
            pipeline_tracked_labels: vec!["coord".to_string()],
            pipeline_repos: vec![("api".to_string(), "acme/api".to_string())],
            pipeline_repo_paths,
            open_issues: vec![OpenIssue {
                repo_name: "api".to_string(),
                number: 42,
                title: "Milestone member issue".to_string(),
                body: String::new(),
                state: "open".to_string(),
                labels: vec!["coord".to_string()],
                milestone_number: Some(9),
                milestone_title: Some("v1.0".to_string()),
            }],
            milestone_work_orders: vec![MilestoneWorkOrder {
                repo_name: "api".to_string(),
                tracking_issue: 751,
                milestone_title: "v1.0".to_string(),
                nodes: vec![MilestoneWorkOrderNode {
                    issue_number: 42,
                    rank: 0,
                    ready: true,
                    next_up: true,
                    blocked_on: vec![],
                }],
            }],
            ..BoardData::default()
        };
        let mut app = make_test_app(data);
        app.pipeline_issues = vec![
            PipelineIssue {
                number: 42,
                title: "Milestone member issue".to_string(),
                body: String::new(),
                repo_slug: "acme/api".to_string(),
                coord_repo: Some("api".to_string()),
                matched_labels: vec!["coord".to_string()],
                all_labels: vec!["coord".to_string(), "status:ready".to_string()],
                is_closed: false,
            },
            PipelineIssue {
                number: 99,
                title: "Ordinary issue, no work order".to_string(),
                body: String::new(),
                repo_slug: "acme/api".to_string(),
                coord_repo: Some("api".to_string()),
                matched_labels: vec!["coord".to_string()],
                all_labels: vec!["coord".to_string(), "status:ready".to_string()],
                is_closed: false,
            },
        ];
        app.rebuild_pipeline_sidebar(None);
        app.active_view = SidebarView::Pipeline;
        app.pipeline_sel = Some(selected_idx);
        app
    }

    #[test]
    fn acceptance_menu_items_present_only_for_milestone_work_order_member() {
        // #1060: unlike Gate A dispatch/sign-off (#1059, epic-row-only),
        // "Author acceptance tests" / "Record acceptance" apply to ordinary
        // member issues of a milestone's work order.
        let member_app = make_pipeline_app_for_acceptance_menu_test(0, "/nonexistent/api-repo");
        let items = member_app.context_menu_items_for_pipeline_row(
            Some(42),
            &PipelineRowLifecycle::New,
            Some("api"),
        );
        assert!(
            items.iter().any(|i| i.action_id.as_deref() == Some("author-acceptance-tests")),
            "work-order member row must offer 'Author acceptance tests'"
        );
        assert!(
            items.iter().any(|i| i.action_id.as_deref() == Some("record-acceptance")),
            "work-order member row must offer 'Record acceptance'"
        );

        let non_member_app = make_pipeline_app_for_acceptance_menu_test(1, "/nonexistent/api-repo");
        let items = non_member_app.context_menu_items_for_pipeline_row(
            Some(99),
            &PipelineRowLifecycle::New,
            Some("api"),
        );
        assert!(
            !items.iter().any(|i| i.action_id.as_deref() == Some("author-acceptance-tests")),
            "non-member row must NOT offer 'Author acceptance tests'"
        );
        assert!(
            !items.iter().any(|i| i.action_id.as_deref() == Some("record-acceptance")),
            "non-member row must NOT offer 'Record acceptance'"
        );
    }

    #[test]
    fn author_acceptance_tests_item_disabled_until_contract_exists_on_disk() {
        // #1060: "Author acceptance tests" is only meaningful once Gate A's
        // contract.md exists — the independent test-author reads it from its
        // own checkout, so JIT authoring against a missing contract is a
        // guaranteed failure. Gated via a local-filesystem check
        // (`gate_a_contract_exists_for`), mirroring the coordinator's own
        // `coord.acceptance.gate_a_contract_path` layout.
        let tid = format!("{:?}", std::thread::current().id()).replace(['(', ')'], "");
        let tmp = std::env::temp_dir().join(format!("coord-tui-test-gate-a-contract-{}", tid));
        let _ = std::fs::remove_dir_all(&tmp);

        let app = make_pipeline_app_for_acceptance_menu_test(0, tmp.to_str().unwrap());
        let items = app.context_menu_items_for_pipeline_row(
            Some(42),
            &PipelineRowLifecycle::New,
            Some("api"),
        );
        let author_item = items
            .iter()
            .find(|i| i.action_id.as_deref() == Some("author-acceptance-tests"))
            .expect("work-order member row must offer 'author-acceptance-tests'");
        assert!(
            author_item.disabled,
            "must be disabled before contract.md exists on disk"
        );

        // Write the contract at the expected ms-9 path (milestone #9, from
        // the fixture's `open_issues` entry) and re-check.
        let contract_dir = tmp.join("tests").join("acceptance").join("ms-9");
        std::fs::create_dir_all(&contract_dir).unwrap();
        std::fs::write(contract_dir.join("contract.md"), "# Gate A contract\n").unwrap();

        let app = make_pipeline_app_for_acceptance_menu_test(0, tmp.to_str().unwrap());
        let items = app.context_menu_items_for_pipeline_row(
            Some(42),
            &PipelineRowLifecycle::New,
            Some("api"),
        );
        let author_item = items
            .iter()
            .find(|i| i.action_id.as_deref() == Some("author-acceptance-tests"))
            .expect("work-order member row must offer 'author-acceptance-tests'");
        assert!(
            !author_item.disabled,
            "must enable once contract.md exists on disk"
        );

        let _ = std::fs::remove_dir_all(&tmp);
    }

