    // ── Leg 3c / A3 (#517, #581): test-verdict routing ────────────────────

    fn done_work_with_test_state(issue: u64, repo: &str, state: &str) -> Assignment {
        let mut a = done_work_with_branch(issue, repo);
        a.test_state = Some(state.to_string());
        a
    }

    fn arm_test_verdict(
        app: &mut CoordApp,
        repo: &str,
        issue: u64,
        work_aid: &str,
        prior: Option<&str>,
    ) {
        app.armed_for_test_verdict.insert(
            (repo.to_string(), issue),
            ArmedTestVerdict {
                coord_repo: repo.to_string(),
                repo_slug: repo.to_string(),
                issue_num: issue,
                work_aid: work_aid.to_string(),
                prior_test_state: prior.map(|s| s.to_string()),
            },
        );
    }

    #[test]
    fn detect_test_verdict_failed_raises_test_fix() {
        let mut app =
            make_app_with_assignments(vec![done_work_with_test_state(10, "repo-a", "failed")]);
        arm_test_verdict(&mut app, "repo-a", 10, "id-10-done", None);
        assert!(app.detect_test_verdict());
        let p = app.pending_test_fix.as_ref().expect("test-fix prompt raised");
        assert_eq!(p.issue_num, 10);
        assert!(app.pending_merge.is_none());
        // Armed entry consumed so it doesn't re-route next tick.
        assert!(app.armed_for_test_verdict.is_empty());
    }

    #[test]
    fn detect_test_verdict_passed_raises_review() {
        let mut app =
            make_app_with_assignments(vec![done_work_with_test_state(10, "repo-a", "passed")]);
        arm_test_verdict(&mut app, "repo-a", 10, "id-10-done", None);
        assert!(app.detect_test_verdict());
        // Test precedes Review: a passed smoke test offers the review next.
        let p = app.pending_auto_review.as_ref().expect("review prompt raised");
        assert_eq!(p.issue_num, 10);
        assert!(app.pending_test_fix.is_none());
        assert!(app.pending_merge.is_none());
        assert!(app.armed_for_test_verdict.is_empty());
    }

    #[test]
    fn detect_test_verdict_ignores_unchanged_prior_state() {
        // The work was already failed at arm time → no NEW verdict, so the
        // detector must not re-fire (edge-triggered on a state change).
        let mut app =
            make_app_with_assignments(vec![done_work_with_test_state(10, "repo-a", "failed")]);
        arm_test_verdict(&mut app, "repo-a", 10, "id-10-done", Some("failed"));
        assert!(!app.detect_test_verdict());
        assert!(app.pending_test_fix.is_none());
        assert!(app.pending_merge.is_none());
        assert!(app
            .armed_for_test_verdict
            .contains_key(&("repo-a".to_string(), 10)));
    }

    #[test]
    fn detect_test_verdict_no_fire_without_verdict() {
        // Work has no test verdict yet → nothing to route.
        let mut app = make_app_with_assignments(vec![done_work_with_branch(10, "repo-a")]);
        arm_test_verdict(&mut app, "repo-a", 10, "id-10-done", None);
        assert!(!app.detect_test_verdict());
        assert!(app.pending_test_fix.is_none());
        assert!(app.pending_merge.is_none());
    }

    #[test]
    fn detect_test_verdict_defers_while_test_pane_is_live() {
        // #602: the operator usually records the verdict (`coord test --fail`)
        // from *inside* the still-attended interactive test pane.  The detector
        // must NOT fire while a live session for that issue is open — otherwise
        // the fail→fix prompt pops over the live pane and confirming it would
        // replace the pane's PTY (the launch insert() is keyed by issue).  It
        // must keep the arm and fire only once the test pane closes.
        let mut app =
            make_app_with_assignments(vec![done_work_with_test_state(10, "repo-a", "failed")]);
        arm_test_verdict(&mut app, "repo-a", 10, "id-10-done", None);

        // A live (non-exited) interactive session for this issue_key.
        let cwd = std::env::temp_dir();
        let sess =
            quadraui::terminal_engine::TerminalSession::spawn(80, 24, "/bin/sh", &cwd, 100)
                .expect("spawn /bin/sh");
        app.detail_terminal_sessions
            .insert(("repo-a".to_string(), 10), sess);

        // Deferred: no prompt raised, arm preserved for a later tick.
        assert!(!app.detect_test_verdict(), "must defer while the pane is live");
        assert!(app.pending_test_fix.is_none());
        assert!(app.pending_merge.is_none());
        assert!(
            app.armed_for_test_verdict
                .contains_key(&("repo-a".to_string(), 10)),
            "arm must persist so it fires once the test pane closes"
        );

        // Operator closed the test pane → now the offer fires.
        app.detail_terminal_sessions.clear();
        assert!(app.detect_test_verdict(), "fires once the pane is gone");
        assert_eq!(
            app.pending_test_fix
                .as_ref()
                .expect("fail→fix prompt raised after the pane closed")
                .issue_num,
            10,
        );
        assert!(app.armed_for_test_verdict.is_empty());
    }

    #[test]
    fn issues_by_repo_includes_empty_repos_from_machines() {
        let mut app = make_test_app(BoardData {
            machines: vec![Machine {
                name: "m1".to_string(),
                host: String::new(),
                reachable: true,
                active_count: 0,
                repos: vec!["empty-repo".to_string()],
                version: None,
                worktree_bytes: 0,
            }],
            ..BoardData::default()
        });
        app.rebuild_board_sidebar();
        let grouped = app.issues_by_repo();
        // Empty repo should appear with 0 issues.
        assert_eq!(grouped.len(), 1);
        assert_eq!(grouped[0].0, "empty-repo");
        assert!(grouped[0].1.is_empty());
    }

