    /// #628: the production `rebuild_pipeline_sidebar` path exposes the THREE
    /// lifecycle sections in canonical order New → In-progress → Done. Neither
    /// status:ready (Pending) nor status:refining (Refining) splits a bucket —
    /// they gate nothing — so both fold into New.
    #[test]
    fn rebuild_pipeline_sidebar_exposes_three_lifecycle_sections() {
        let mut app = make_pipeline_app();
        // The fixture starts with two issues, both `status:ready`
        // (Pending).  Add one issue per remaining state.
        // New: no `status:*` label.
        app.pipeline_issues.push(PipelineIssue {
            number: 101,
            title: "Brand new".to_string(),
            body: String::new(),
            repo_slug: "acme/api".to_string(),
            coord_repo: Some("api".to_string()),
            matched_labels: vec!["coord".to_string()],
            all_labels: vec!["coord".to_string()],
            is_closed: false,
        });
        // Legacy `status:refining` → folds into New (#628, Refining eliminated).
        app.pipeline_issues.push(PipelineIssue {
            number: 102,
            title: "Legacy refining".to_string(),
            body: String::new(),
            repo_slug: "acme/api".to_string(),
            coord_repo: Some("api".to_string()),
            matched_labels: vec!["coord".to_string()],
            all_labels: vec!["coord".to_string(), "status:refining".to_string()],
            is_closed: false,
        });
        // In-progress: status:ready + active work assignment.
        app.pipeline_issues.push(PipelineIssue {
            number: 103,
            title: "Actively working".to_string(),
            body: String::new(),
            repo_slug: "acme/api".to_string(),
            coord_repo: Some("api".to_string()),
            matched_labels: vec!["coord".to_string()],
            all_labels: vec!["coord".to_string(), "status:ready".to_string()],
            is_closed: false,
        });
        app.data
            .assignments
            .push(make_assignment_typed("running", 103, "api", Some("work")));
        // Done: closed.
        app.pipeline_issues.push(PipelineIssue {
            number: 104,
            title: "Closed".to_string(),
            body: String::new(),
            repo_slug: "acme/api".to_string(),
            coord_repo: Some("api".to_string()),
            matched_labels: vec!["coord".to_string()],
            all_labels: vec!["coord".to_string()],
            is_closed: true,
        });
        // #728: issue #104 has no finished_at; use All window so it appears.
        app.done_window = DoneWindow::All;
        app.rebuild_pipeline_sidebar(None);

        // #815: In-progress moves to the top; the pre-dispatch states follow.
        // status:ready and status:refining gate nothing, so the fixture's
        // status:ready issues + #101 (no label) + #102 (status:refining) all
        // sit in New.  Order is: In-progress → New → Done.
        assert_eq!(
            app.pipeline_state_section_names,
            vec!["in-progress", "new", "done"],
            "In-progress must appear first (#815), followed by New then Done",
        );
    }

