    #[test]
    fn apply_pending_data_skips_empty_degraded_tick() {
        // #620: a fully-empty payload (load_data_remote returns
        // BoardData::default() on a connect/timeout/parse failure) must NOT
        // replace populated data — doing so wiped the Pipeline and dropped
        // every live terminal, bouncing the operator out of an attended
        // session.  The guard keeps the last good data + raises a soft warning.
        let mut app = make_pipeline_app();
        let issues_before = app.pipeline_issues.clone();
        // A spawn-error entry stands in for a live terminal (a real PTY would
        // be heavier here); the early-bail must happen BEFORE the prune, so it
        // survives the degraded tick.
        app.detail_terminal_spawn_errors
            .insert(("acme/api".to_string(), 42), "live".to_string());

        // Deliver the failure sentinel: an entirely empty BoardData.
        let (tx, rx) = std::sync::mpsc::channel();
        tx.send(BoardData::default()).unwrap();
        app.pending_data = Some(rx);

        assert!(
            app.apply_pending_data(),
            "degraded tick still returns true so the warning redraws",
        );
        // Last good data is preserved — NOT clobbered with the empty payload.
        assert!(
            !app.data.machines.is_empty(),
            "machines must survive a degraded tick",
        );
        assert_eq!(
            app.pipeline_issues, issues_before,
            "pipeline issues must survive a degraded tick",
        );
        assert!(
            app.detail_terminal_spawn_errors
                .contains_key(&("acme/api".to_string(), 42)),
            "terminals must NOT be pruned on a degraded tick",
        );
        assert!(app.fetch_error.is_some(), "a soft warning is surfaced");
        assert!(app.pending_data.is_none(), "the receiver is consumed");
    }

    #[test]
    #[cfg(unix)]
    fn apply_pending_data_keeps_terminals_when_pipeline_empties_partially() {
        // #620: a PARTIAL degradation slips past the full-empty guard —
        // machines + open_issues are present, but pipeline_tracked_labels
        // momentarily drops out (a board_meta hiccup), so pipeline_issues_from_cache
        // returns empty → live_keys empty.  The retain must NOT then nuke a live
        // embedded terminal; an empty live set while we still hold sessions is a
        // near-certain degradation, so the prune is skipped this tick.
        let mut app = make_pipeline_app();
        let cwd = std::env::temp_dir();
        let sess =
            quadraui::terminal_engine::TerminalSession::spawn(80, 24, "/bin/sh", &cwd, 100)
                .expect("spawn /bin/sh");
        app.detail_terminal_sessions
            .insert(("acme/api".to_string(), 42), sess);

        // Non-empty payload (guard inert) but tracked_labels dropped → the
        // Pipeline derives to empty.
        let fresh = BoardData {
            pipeline_tracked_labels: vec![], // the partial degradation
            pipeline_repos: vec![("api".to_string(), "acme/api".to_string())],
            machines: vec![Machine {
                name: "m1".to_string(),
                host: String::new(),
                reachable: true,
                active_count: 0,
                repos: vec!["api".to_string()],
                version: None,
                worktree_bytes: 0,
            }],
            open_issues: vec![OpenIssue {
                repo_name: "api".to_string(),
                number: 42,
                title: "still here".to_string(),
                body: String::new(),
                state: "open".to_string(),
                labels: vec!["coord".to_string()],
                milestone_number: None,
                milestone_title: None,
            }],
            ..BoardData::default()
        };
        let (tx, rx) = std::sync::mpsc::channel();
        tx.send(fresh).unwrap();
        app.pending_data = Some(rx);

        assert!(app.apply_pending_data(), "data was consumed");
        assert!(
            app.pipeline_issues.is_empty(),
            "pre-condition: dropped tracked_labels empties the Pipeline",
        );
        assert!(
            app.detail_terminal_sessions
                .contains_key(&("acme/api".to_string(), 42)),
            "a live terminal must survive an empty-pipeline tick (no mass prune)",
        );
    }

    // ── #290: sidebar dedup during open→closed transition ────────────────

    #[test]
    fn pipeline_groups_no_duplicate_row_during_open_to_closed_transition() {
        // #290: pipeline_issues can momentarily contain two entries for the
        // same issue — one from the gh --state=open query (seen as
        // "in-progress") and one from --state=closed (seen as "done").
        // pipeline_groups_for_repo must deduplicate so the issue appears
        // exactly once, with the more-recent (closed) entry winning.
        let mut app = make_pipeline_app();

        // Issue #42 (index 0) is already in pipeline_issues as open+ready.
        // Give it a running assignment so its lifecycle is "in-progress".
        app.data
            .assignments
            .push(make_assignment_typed("running", 42, "api", Some("work")));

        // Simulate the race: the --state=closed query also returned #42 as
        // closed.  Appending puts it at a higher index (later = wins dedup).
        app.pipeline_issues.push(PipelineIssue {
            number: 42,
            title: "Add cool thing".to_string(),
            body: String::new(),
            repo_slug: "acme/api".to_string(),
            coord_repo: Some("api".to_string()),
            matched_labels: vec!["coord".to_string()],
            all_labels: vec!["coord".to_string()],
            is_closed: true,
        });

        let groups = app.pipeline_groups_for_repo("api");

        // Count how many times #42 appears across all lifecycle sections.
        let count_42: usize = groups
            .iter()
            .flat_map(|(_, idxs)| idxs.iter())
            .filter(|&&i| app.pipeline_issues[i].number == 42)
            .count();
        assert_eq!(
            count_42, 1,
            "issue #42 must appear exactly once; appeared {count_42} time(s)",
        );

        // The surviving entry must be the closed (done) one.
        let in_done = groups
            .iter()
            .find(|(k, _)| *k == "done")
            .map(|(_, idxs)| idxs.iter().any(|&i| app.pipeline_issues[i].number == 42))
            .unwrap_or(false);
        assert!(
            in_done,
            "closed entry must win: issue #42 must be in the 'done' section",
        );

        // The in-progress section must NOT contain #42.
        let in_progress = groups
            .iter()
            .find(|(k, _)| *k == "in-progress")
            .map(|(_, idxs)| idxs.iter().any(|&i| app.pipeline_issues[i].number == 42))
            .unwrap_or(false);
        assert!(
            !in_progress,
            "open (stale) entry must be suppressed: #42 must not appear in 'in-progress'",
        );
    }

    // ── Pipeline selection preservation across pipeline_issues swaps ──────

    /// The canonical regression test for "the 15-second refresh keeps
    /// jumping me back to the top".  Reproduces the poll_pipeline_loader
    /// pattern: capture the selection identity, swap pipeline_issues,
    /// rebuild with the captured identity.
    #[test]
    fn rebuild_pipeline_sidebar_preserves_selection_when_prev_sel_captured_before_swap() {
        let mut app = make_pipeline_app();
        // Default selection lands on #42 (api).
        assert_eq!(app.pipeline_sel, Some(0));
        assert_eq!(app.pipeline_issues[0].number, 42);

        // Capture BEFORE the swap (the fix).
        let prev_sel = app.capture_pipeline_selection_id();
        assert_eq!(prev_sel, Some(("acme/api".to_string(), 42)));

        // Simulate a refresh that prepends a new issue, shifting #42 to index 1.
        let mut new_issues = vec![PipelineIssue {
            number: 7,
            title: "New backlog item".to_string(),
            body: String::new(),
            repo_slug: "acme/api".to_string(),
            coord_repo: Some("api".to_string()),
            matched_labels: vec!["coord".to_string()],
            all_labels: vec!["coord".to_string()],
            is_closed: false,
        }];
        new_issues.extend(app.pipeline_issues.clone());
        app.pipeline_issues = new_issues;

        app.rebuild_pipeline_sidebar(prev_sel);

        let selected_number = app
            .pipeline_sel
            .and_then(|i| app.pipeline_issues.get(i))
            .map(|i| i.number);
        assert_eq!(
            selected_number,
            Some(42),
            "selection must follow #42 even though its index moved from 0 to 1",
        );
    }

    /// Documents the BUG path: callers that swap pipeline_issues without
    /// capturing prev_sel first end up restoring the wrong issue.  Locks
    /// in the expectation so a future regression in poll_pipeline_loader
    /// (e.g. someone removing the capture call) shows up as a failing
    /// test rather than a silent selection-jump.
    #[test]
    fn rebuild_pipeline_sidebar_without_prev_sel_reads_stale_index() {
        let mut app = make_pipeline_app();
        assert_eq!(app.pipeline_sel, Some(0));
        assert_eq!(app.pipeline_issues[0].number, 42);

        // Swap WITHOUT capturing prev_sel first — the buggy pattern.
        // #225: include `status:ready` so the new issue lands in the
        // visible Pipeline:New (formerly "pending") section.
        let mut new_issues = vec![PipelineIssue {
            number: 7,
            title: "New backlog item".to_string(),
            body: String::new(),
            repo_slug: "acme/api".to_string(),
            coord_repo: Some("api".to_string()),
            matched_labels: vec!["coord".to_string()],
            all_labels: vec!["coord".to_string(), "status:ready".to_string()],
            is_closed: false,
        }];
        new_issues.extend(app.pipeline_issues.clone());
        app.pipeline_issues = new_issues;

        // No override → internal fallback reads pipeline_sel(=Some(0))
        // against the new list → captures #7 (not #42) → restores #7.
        app.rebuild_pipeline_sidebar(None);

        let selected_number = app
            .pipeline_sel
            .and_then(|i| app.pipeline_issues.get(i))
            .map(|i| i.number);
        assert_eq!(
            selected_number,
            Some(7),
            "documents the bug: stale index reads the wrong issue from the new list",
        );
    }

