    /// The 15s pipeline refresh used to reset the sidebar's panel scroll
    /// to 0, which yanked the visible area to the top even when the
    /// selection itself was restored.  Test that the scroll offset is
    /// preserved across a rebuild_pipeline_sidebar call.
    #[test]
    fn rebuild_pipeline_sidebar_preserves_panel_scroll() {
        let mut app = make_pipeline_app();
        // Set a non-zero panel scroll (simulating the user having scrolled).
        app.pipeline_sidebar.set_panel_scroll(42.0);
        assert_eq!(app.pipeline_sidebar.panel_scroll(), 42.0);

        // Simulate a refresh that doesn't change the issue list.
        app.rebuild_pipeline_sidebar(None);

        assert_eq!(
            app.pipeline_sidebar.panel_scroll(),
            42.0,
            "panel scroll must survive rebuild — otherwise the view yanks to top on refresh",
        );
    }

    /// State-section collapse state must survive a rebuild — without this, the
    /// user collapses the large "Done" section and watches it re-expand on
    /// every 15 s refresh.
    #[test]
    fn rebuild_pipeline_sidebar_preserves_section_collapsed_state() {
        let mut app = make_pipeline_app();
        // Add a closed (Done) issue so we have both "Pending" (state idx 0)
        // and "Done" (state idx 1) sections — the pipeline fixture already
        // seeds a `status:ready` issue (Pending).
        app.pipeline_issues.push(PipelineIssue {
            number: 55,
            title: "Finished task".to_string(),
            body: String::new(),
            repo_slug: "acme/api".to_string(),
            coord_repo: Some("api".to_string()),
            matched_labels: vec!["coord".to_string()],
            all_labels: vec!["coord".to_string()],
            is_closed: true,
        });
        // #728: #55 has no finished_at; use All window so it appears in Done.
        // (pipeline_lifecycle_section returns "done" for is_closed=true).
        app.done_window = DoneWindow::All;
        app.rebuild_pipeline_sidebar(None);
        // #628: the fixture's status:ready issues are now "new" (status:ready
        // gates nothing). With the closed #55 → "done", sections are New + Done.
        // Section 0 = FILTER, 1 = "New", 2 = "Done".
        assert_eq!(app.pipeline_state_section_names, vec!["new", "done"]);
        // #815: Done starts collapsed by default; New starts expanded.
        assert!(!app.pipeline_sidebar.is_collapsed(1)); // New: expanded by default
        assert!(app.pipeline_sidebar.is_collapsed(2));  // Done: collapsed by default (#815)

        // Collapse New and explicitly expand Done (user action).
        app.pipeline_sidebar.set_collapsed(1, true);
        app.pipeline_sidebar.set_collapsed(2, false);
        assert!(app.pipeline_sidebar.is_collapsed(1));
        assert!(!app.pipeline_sidebar.is_collapsed(2));

        // Rebuild — collapse state must be preserved across rebuild.
        app.rebuild_pipeline_sidebar(None);

        assert!(
            app.pipeline_sidebar.is_collapsed(1),
            "New section collapse state must survive rebuild",
        );
        assert!(
            !app.pipeline_sidebar.is_collapsed(2),
            "Done section stays expanded (user explicitly expanded it; persists across rebuild)",
        );
    }

    /// Collapse state is keyed by state name, not section index — when the
    /// section order changes (e.g. a section appears earlier in the display
    /// order), existing sections' collapse state must follow them to their
    /// new indices.
    #[test]
    fn rebuild_pipeline_sidebar_collapse_state_follows_state_through_reorder() {
        let mut app = make_pipeline_app();
        // #628: everything pre-work is now "new", so to exercise a section
        // REORDER we start with a single Done issue, collapse it, then add a New
        // issue — "new" sorts before "done", pushing Done from section 1 to 2.
        app.pipeline_issues.clear();
        app.pipeline_issues.push(PipelineIssue {
            number: 90,
            title: "Done".to_string(),
            body: String::new(),
            repo_slug: "acme/api".to_string(),
            coord_repo: Some("api".to_string()),
            matched_labels: vec!["coord".to_string()],
            all_labels: vec!["coord".to_string()],
            is_closed: true,
        });
        // #728: issue #90 has no finished_at; use All window so it appears.
        app.done_window = DoneWindow::All;
        app.rebuild_pipeline_sidebar(None);
        assert_eq!(app.pipeline_state_section_names, vec!["done"]);
        app.pipeline_sidebar.set_collapsed(1, true); // collapse Done (section 1)
        assert!(app.pipeline_sidebar.is_collapsed(1));

        // Add a New (open) issue — "new" sorts before "done", so Done moves to
        // section 2. Collapse state is keyed by NAME, so it must follow Done.
        app.pipeline_issues.push(PipelineIssue {
            number: 91,
            title: "New work".to_string(),
            body: String::new(),
            repo_slug: "acme/api".to_string(),
            coord_repo: Some("api".to_string()),
            matched_labels: vec!["coord".to_string()],
            all_labels: vec!["coord".to_string()],
            is_closed: false,
        });
        app.rebuild_pipeline_sidebar(None);

        assert_eq!(app.pipeline_state_section_names, vec!["new", "done"]);
        assert!(
            !app.pipeline_sidebar.is_collapsed(1),
            "New section must not be retroactively collapsed",
        );
        assert!(
            app.pipeline_sidebar.is_collapsed(2),
            "Done section collapse state followed from section 1 to section 2",
        );
    }

    /// The combined scenario from the user's report: refresh swaps
    /// pipeline_issues, selection is restored via the explicit override,
    /// AND the scroll offset is preserved so the visible area doesn't move.
    #[test]
    fn rebuild_pipeline_sidebar_preserves_both_selection_and_scroll() {
        let mut app = make_pipeline_app();
        app.pipeline_sel = Some(0);
        app.pipeline_sidebar.set_panel_scroll(17.5);

        let prev_sel = app.capture_pipeline_selection_id();
        let mut new_issues = vec![PipelineIssue {
            number: 7,
            title: "Just appeared".to_string(),
            body: String::new(),
            repo_slug: "acme/api".to_string(),
            coord_repo: Some("api".to_string()),
            matched_labels: vec!["coord".to_string()],
            all_labels: vec!["coord".to_string()],
            is_closed: false,
        }];
        new_issues.extend(app.pipeline_issues.clone());
        app.pipeline_issues = new_issues;

        app.rebuild_pipeline_sidebar(prev_sel);

        assert_eq!(
            app.pipeline_sel
                .and_then(|i| app.pipeline_issues.get(i))
                .map(|i| i.number),
            Some(42),
            "selection still on the original issue",
        );
        assert_eq!(
            app.pipeline_sidebar.panel_scroll(),
            17.5,
            "scroll preserved alongside selection",
        );
    }

    // ── Shared SidebarFilter helper ───────────────────────────────────────

    #[test]
    fn sidebar_filter_matches_empty_query_matches_all() {
        let f = SidebarFilter::default();
        assert!(f.matches(42, "anything"));
        assert!(f.matches(1, ""));
    }

    #[test]
    fn sidebar_filter_matches_on_number_and_title_case_insensitively() {
        let mut f = SidebarFilter::default();
        f.set_value("42");
        assert!(f.matches(42, "unrelated title"), "matches on issue number");
        assert!(!f.matches(99, "unrelated title"), "no substring → no match");

        f.set_value("COOL");
        assert!(
            f.matches(7, "Add cool thing"),
            "case-insensitive title match"
        );
        assert!(!f.matches(7, "boring"), "no title substring → no match");
    }

    #[test]
    fn sidebar_filter_edit_ops_track_cursor() {
        let mut f = SidebarFilter::default();
        f.insert_char('a');
        f.insert_char('b');
        assert_eq!(f.query, "ab");
        assert_eq!(f.cursor, 2);
        f.backspace();
        assert_eq!(f.query, "a");
        assert_eq!(f.cursor, 1);
        f.cursor_left();
        assert_eq!(f.cursor, 0);
        f.cursor_right();
        assert_eq!(f.cursor, 1);
        f.set_value("hello");
        assert_eq!(f.query, "hello");
        assert_eq!(f.cursor, 5);
        f.focused = true;
        f.clear();
        assert_eq!(f.query, "");
        assert_eq!(f.cursor, 0);
        assert!(!f.focused, "clear drops focus");
    }

    // ── #646/#566: filter blur (ESC, row-click, main-click) ──────────────

    /// ESC while the filter is focused AND non-empty blurs (clear + unfocus).
    #[test]
    fn esc_blur_board_filter_focused_with_query() {
        let mut app = make_app_default();
        app.board_search.focused = true;
        app.board_search.insert_char('h');
        app.board_search.insert_char('i');
        app.rebuild_board_sidebar();
        assert!(app.board_sidebar.form_has_focus(0), "precondition: form focused");

        // Replicate what the keyboard ESC arm does:
        app.board_search.clear(); // sets focused = false
        app.board_sidebar.focus_form(0, false);
        app.rebuild_board_sidebar();

        assert!(!app.board_search.focused, "filter must be unfocused after ESC");
        assert!(app.board_search.is_empty(), "filter must be cleared after ESC");
        assert!(!app.board_sidebar.form_has_focus(0), "quadraui form must be unfocused");
    }

    /// ESC while the filter is focused AND empty blurs instead of quitting (#566).
    #[test]
    fn esc_blur_board_filter_focused_and_empty() {
        let mut app = make_app_default();
        app.board_search.focused = true;
        app.rebuild_board_sidebar();
        // filter is empty — old code fell through to quit; new code blurs
        assert!(app.board_search.is_empty(), "precondition: empty");
        assert!(app.board_search.focused, "precondition: focused");

        // Replicate the #646 ESC arm:
        app.board_search.clear();
        app.board_sidebar.focus_form(0, false);
        app.rebuild_board_sidebar();

        assert!(!app.board_search.focused, "ESC on empty focused filter must blur, not quit");
        assert!(!app.board_sidebar.form_has_focus(0), "quadraui form must be unfocused");
    }

    /// ESC while the pipeline filter is focused blurs it.
    #[test]
    fn esc_blur_pipeline_filter_when_focused() {
        let mut app = make_pipeline_app();
        app.pipeline_search.focused = true;
        app.pipeline_search.insert_char('x');
        app.rebuild_pipeline_sidebar(None);

        // Replicate the #646 ESC arm:
        app.pipeline_search.clear();
        app.pipeline_sidebar.focus_form(0, false);
        app.rebuild_pipeline_sidebar(None);

        assert!(!app.pipeline_search.focused, "pipeline filter must blur on ESC");
        assert!(!app.pipeline_sidebar.form_has_focus(0), "pipeline quadraui form must be unfocused");
    }

    /// Focusing the filter, then clearing + rebuilding, leaves it unfocused
    /// (verifies focus_form survives rebuild).
    #[test]
    fn filter_blur_survives_rebuild() {
        let mut app = make_app_default();
        // Focus then immediately blur without the sidebar rebuild in between.
        app.board_search.focused = true;
        app.board_sidebar.focus_form(0, true);
        // Now blur:
        app.board_search.focused = false;
        app.board_sidebar.focus_form(0, false);
        app.rebuild_board_sidebar(); // rebuild must not re-focus
        assert!(!app.board_search.focused);
        assert!(!app.board_sidebar.form_has_focus(0), "rebuild must not re-apply focus when board_search.focused is false");
    }

