    #[test]
    fn poll_remote_sessions_replaces_snapshot_when_ready() {
        let mut app = make_app_default();
        // Startup local-only snapshot is empty; a remote fetch then lands.
        assert!(app.live_tmux_sessions.is_empty());
        let (tx, rx) = std::sync::mpsc::channel();
        tx.send(vec![LiveTmuxSession {
            assignment_id: "aid-remote".to_string(),
            issue_number: Some(9),
            repo_name: Some("api".to_string()),
            issue_title: None,
            machine: None,
            pane_dead: false,
            pending_sweep_count: 0,
            attached: false,
        }])
        .unwrap();
        app.pending_remote_sessions = Some(rx);

        assert!(app.poll_remote_sessions(), "should report an update");
        assert_eq!(app.live_tmux_sessions.len(), 1);
        assert_eq!(app.live_tmux_sessions[0].assignment_id, "aid-remote");
        // The receiver is consumed — no repeat updates.
        assert!(app.pending_remote_sessions.is_none());
        assert!(!app.poll_remote_sessions());
    }

    #[test]
    fn poll_remote_sessions_noop_while_empty() {
        let mut app = make_app_default();
        let (_tx, rx) = std::sync::mpsc::channel::<Vec<LiveTmuxSession>>();
        app.pending_remote_sessions = Some(rx);
        // Nothing sent yet → no update, receiver retained for a later poll.
        assert!(!app.poll_remote_sessions());
        assert!(app.pending_remote_sessions.is_some());
    }

    // #559 — re-arm on refresh
    #[test]
    fn refresh_rearms_remote_session_fetch_when_idle() {
        let mut app = make_app_default();
        // Drain the startup arm (poll with nothing sent → stays pending).
        // For this test we want to start in the "one-shot already consumed" state.
        app.pending_remote_sessions = None;
        assert!(app.pending_remote_sessions.is_none());
        app.refresh();
        assert!(
            app.pending_remote_sessions.is_some(),
            "refresh() must re-arm the remote session fetch when it was None"
        );
    }

    #[test]
    fn refresh_does_not_double_arm_while_fetch_in_flight() {
        let mut app = make_app_default();
        // An in-flight fetch is already armed.
        let (_tx, rx) = std::sync::mpsc::channel::<Vec<LiveTmuxSession>>();
        app.pending_remote_sessions = Some(rx);
        let ptr_before = app.pending_remote_sessions.as_ref().unwrap()
            as *const std::sync::mpsc::Receiver<Vec<LiveTmuxSession>>;
        app.refresh();
        let ptr_after = app.pending_remote_sessions.as_ref().unwrap()
            as *const std::sync::mpsc::Receiver<Vec<LiveTmuxSession>>;
        assert_eq!(
            ptr_before, ptr_after,
            "refresh() must not replace an in-flight receiver"
        );
    }

    // #559 — merge behaviour in poll_remote_sessions
    #[test]
    fn poll_remote_sessions_preserves_pending_entry_when_not_in_discovery() {
        // An optimistic "pending-" entry for (api, #42) was added at launch.
        // The discovery result comes back WITHOUT that session (e.g. the
        // session was just starting up and isn't discoverable yet).
        // The pending entry must survive so the card stays Live.
        let mut app = make_app_default();
        app.live_tmux_sessions = vec![LiveTmuxSession {
            assignment_id: "pending-api-42".to_string(),
            issue_number: Some(42),
            repo_name: Some("api".to_string()),
            issue_title: None,
            machine: None,
            pane_dead: false,
            pending_sweep_count: 0,
            attached: false,
        }];
        let (tx, rx) = std::sync::mpsc::channel();
        // Discovery returns an unrelated session only.
        tx.send(vec![LiveTmuxSession {
            assignment_id: "aid-other".to_string(),
            issue_number: Some(7),
            repo_name: Some("api".to_string()),
            issue_title: None,
            machine: None,
            pane_dead: false,
            pending_sweep_count: 0,
            attached: false,
        }])
        .unwrap();
        app.pending_remote_sessions = Some(rx);

        assert!(app.poll_remote_sessions());
        // Both the optimistic entry AND the discovered entry must be present.
        assert_eq!(app.live_tmux_sessions.len(), 2);
        let ids: Vec<&str> = app
            .live_tmux_sessions
            .iter()
            .map(|s| s.assignment_id.as_str())
            .collect();
        assert!(ids.contains(&"pending-api-42"), "optimistic entry must survive");
        assert!(ids.contains(&"aid-other"), "discovered entry must be present");
    }

    #[test]
    fn poll_remote_sessions_drops_pending_entry_when_covered_by_discovery() {
        // The discovery result now INCLUDES a real session for (api, #42).
        // The optimistic "pending-" entry must be dropped to avoid duplicates.
        let mut app = make_app_default();
        app.live_tmux_sessions = vec![LiveTmuxSession {
            assignment_id: "pending-api-42".to_string(),
            issue_number: Some(42),
            repo_name: Some("api".to_string()),
            issue_title: None,
            machine: None,
            pane_dead: false,
            pending_sweep_count: 0,
            attached: false,
        }];
        let (tx, rx) = std::sync::mpsc::channel();
        tx.send(vec![LiveTmuxSession {
            assignment_id: "real-aid-42".to_string(),
            issue_number: Some(42),
            repo_name: Some("api".to_string()),
            issue_title: None,
            machine: None,
            pane_dead: false,
            pending_sweep_count: 0,
            attached: false,
        }])
        .unwrap();
        app.pending_remote_sessions = Some(rx);

        assert!(app.poll_remote_sessions());
        // Only the real entry remains; the pending one is evicted.
        assert_eq!(app.live_tmux_sessions.len(), 1);
        assert_eq!(app.live_tmux_sessions[0].assignment_id, "real-aid-42");
    }

    // #935 Part A — pending-session survival budget ───────────────────────────

    /// After `PENDING_SESSION_SWEEP_BUDGET` discovery sweeps without the real
    /// session appearing, the optimistic entry must be evicted so a phantom
    /// "Live" badge cannot linger forever.
    #[test]
    fn poll_remote_sessions_evicts_pending_entry_after_budget_exhausted() {
        use crate::app::CoordApp as CA;
        let budget = CA::PENDING_SESSION_SWEEP_BUDGET;

        let mut app = make_app_default();
        // Start with a pending entry that has already consumed the full budget.
        app.live_tmux_sessions = vec![LiveTmuxSession {
            assignment_id: "pending-api-99".to_string(),
            issue_number: Some(99),
            repo_name: Some("api".to_string()),
            issue_title: None,
            machine: None,
            pane_dead: false,
            pending_sweep_count: budget, // already at the limit
            attached: false,
        }];

        // A discovery sweep that does NOT include (api, #99).
        let (tx, rx) = std::sync::mpsc::channel();
        tx.send(vec![]).unwrap(); // empty sweep
        app.pending_remote_sessions = Some(rx);
        assert!(app.poll_remote_sessions());

        // The entry's sweep_count would become budget+1, exceeding the budget
        // → it must be evicted.
        assert!(
            app.live_tmux_sessions.is_empty(),
            "pending entry must be evicted after budget+1 sweeps; sessions={:?}",
            app.live_tmux_sessions.iter().map(|s| &s.assignment_id).collect::<Vec<_>>(),
        );
    }

    /// An entry with sweep_count == budget-1 survives one more uncovered sweep
    /// (bringing it to budget) but is dropped on the next one (budget+1).
    #[test]
    fn poll_remote_sessions_pending_entry_survives_up_to_budget_sweeps() {
        use crate::app::CoordApp as CA;
        let budget = CA::PENDING_SESSION_SWEEP_BUDGET;

        let mut app = make_app_default();
        app.live_tmux_sessions = vec![LiveTmuxSession {
            assignment_id: "pending-api-99".to_string(),
            issue_number: Some(99),
            repo_name: Some("api".to_string()),
            issue_title: None,
            machine: None,
            pane_dead: false,
            pending_sweep_count: 0,
            attached: false,
        }];

        // Drive `budget` uncovered sweeps — the entry must survive each one.
        for sweep in 1..=budget {
            let (tx, rx) = std::sync::mpsc::channel();
            tx.send(vec![]).unwrap();
            app.pending_remote_sessions = Some(rx);
            assert!(app.poll_remote_sessions(), "sweep {sweep} must report update");
            // Rearm for next iteration (poll_remote_sessions clears the receiver).
            assert_eq!(
                app.live_tmux_sessions.len(), 1,
                "pending entry must survive sweep {sweep} (count now {sweep})"
            );
            assert_eq!(
                app.live_tmux_sessions[0].pending_sweep_count, sweep,
                "sweep_count should be {sweep} after sweep {sweep}"
            );
        }

        // One more uncovered sweep → entry must be evicted (count would be budget+1).
        let (tx, rx) = std::sync::mpsc::channel();
        tx.send(vec![]).unwrap();
        app.pending_remote_sessions = Some(rx);
        assert!(app.poll_remote_sessions());
        assert!(
            app.live_tmux_sessions.is_empty(),
            "pending entry must be evicted after budget+1 sweeps"
        );
    }

    /// `issue_session_is_live` must return `false` for a pending entry whose
    /// sweep_count has exceeded the budget and there is no running assignment.
    #[test]
    fn issue_session_is_live_false_for_exhausted_pending_entry_without_assignment() {
        use crate::app::CoordApp as CA;
        let budget = CA::PENDING_SESSION_SWEEP_BUDGET;

        let data = BoardData {
            pipeline_tracked_labels: vec!["coord".to_string()],
            pipeline_repos: vec![("api".to_string(), "acme/api".to_string())],
            open_issues: vec![OpenIssue {
                repo_name: "api".to_string(),
                number: 7,
                title: "issue 7".to_string(),
                body: String::new(),
                state: "open".to_string(),
                labels: vec!["coord".to_string()],
                milestone_number: None,
                milestone_title: None,
            }],
            ..BoardData::default()
        };
        let mut app = make_test_app(data);
        app.pipeline_issues = app.pipeline_issues_from_cache();
        let issue = app.pipeline_issues.iter().find(|i| i.number == 7).unwrap().clone();

        // A pending entry with sweep_count > budget — no real session, no assignment.
        app.live_tmux_sessions = vec![LiveTmuxSession {
            assignment_id: "pending-api-7".to_string(),
            issue_number: Some(7),
            repo_name: Some("api".to_string()),
            issue_title: None,
            machine: None,
            pane_dead: false,
            pending_sweep_count: budget + 1,
            attached: false,
        }];

        assert!(
            !app.issue_session_is_live(&issue),
            "exhausted pending entry without running assignment must not count as live"
        );
    }

