    #[test]
    fn interactive_mode_assignment_type_maps_fix_to_work() {
        // --fix-of continues the work branch as type="work" (cli.py), so a Fix
        // launch must reattach only to a running work session, never a review.
        assert_eq!(interactive_mode_assignment_type(InteractiveLaunchMode::Fix), "work");
        // #1104: --rework-of continues the work branch as type="work" too
        // (dispatch_workers.py `_dispatch_rework_of`), same reattach story as Fix.
        assert_eq!(
            interactive_mode_assignment_type(InteractiveLaunchMode::Continue),
            "work"
        );
        assert_eq!(interactive_mode_assignment_type(InteractiveLaunchMode::Work), "work");
        assert_eq!(interactive_mode_assignment_type(InteractiveLaunchMode::Plan), "work");
        assert_eq!(interactive_mode_assignment_type(InteractiveLaunchMode::Review), "review");
        assert_eq!(interactive_mode_assignment_type(InteractiveLaunchMode::Test), "smoke");
        assert_eq!(interactive_mode_assignment_type(InteractiveLaunchMode::Merge), "merge");
        // #885: Audit is its own board assignment type — never reattaches into
        // a running work/review/smoke/merge session, and nothing else
        // reattaches into a running audit session.
        assert_eq!(interactive_mode_assignment_type(InteractiveLaunchMode::Audit), "audit");
        // #1029: MilestoneChat is its own board assignment type too — and
        // UNLIKE Chat/Troubleshoot/Audit it DOES reattach (see
        // `milestone_chat_reattaches_to_running_session` below).
        assert_eq!(
            interactive_mode_assignment_type(InteractiveLaunchMode::MilestoneChat),
            "milestone-chat"
        );
    }

    /// #1029: unlike Chat/Troubleshoot/Audit (which never reattach — callers
    /// guard), MilestoneChat MUST reattach to an already-running
    /// `type="milestone-chat"` session for the same (repo, tracking_issue) —
    /// the whole point of #1029 bug #4 ("Open milestone chat" on an
    /// already-running session must resume it, not spawn a duplicate).
    #[test]
    fn milestone_chat_reattaches_to_running_session() {
        let mc = make_assignment_typed("running", 973, "api", Some("milestone-chat"));
        let aid = mc.id.clone();
        let mut app = make_app_with_assignments(vec![mc]);
        app.live_tmux_sessions.push(LiveTmuxSession {
            assignment_id: aid.clone(),
            issue_number: Some(973),
            repo_name: Some("api".to_string()),
            issue_title: None,
            machine: None,
            pane_dead: false,
            pending_sweep_count: 0,
            attached: false,
        });

        assert_eq!(
            app.reattachable_session_aid(973, "api", InteractiveLaunchMode::MilestoneChat),
            Some(aid),
        );
        // A DIFFERENT running type for the same issue must not match.
        assert_eq!(
            app.reattachable_session_aid(973, "api", InteractiveLaunchMode::Review),
            None,
        );
    }

    #[test]
    fn reattach_is_mode_aware_fix_skips_running_review() {
        // The kink: "Start fix" reattached into a still-running review session
        // (→ verdict prompt) instead of dispatching a fresh --fix-of.  The
        // reattach must be type-gated: Fix (→ work) ignores a running review,
        // while Review still reattaches to it.
        let mut review = review_of("w", 10, "repo-a", None);
        review.status = "running".to_string();
        let review_aid = review.id.clone();
        let mut app = make_app_with_assignments(vec![review]);
        app.live_tmux_sessions.push(LiveTmuxSession {
            assignment_id: review_aid.clone(),
            issue_number: Some(10),
            repo_name: Some("repo-a".to_string()),
            issue_title: None,
            machine: None,
            pane_dead: false,
            pending_sweep_count: 0,
            attached: false,
        });

        // Fix wants a running "work" session — the only one running is a review.
        assert_eq!(
            app.reattachable_session_aid(10, "repo-a", InteractiveLaunchMode::Fix),
            None,
            "Start fix must NOT reattach into a running review",
        );
        // Review mode legitimately reattaches to its own running review.
        assert_eq!(
            app.reattachable_session_aid(10, "repo-a", InteractiveLaunchMode::Review),
            Some(review_aid),
        );
        // Troubleshoot never reattaches.
        assert_eq!(
            app.reattachable_session_aid(10, "repo-a", InteractiveLaunchMode::Troubleshoot),
            None,
        );
    }

