    // ── #259: right-click context menu primitive ────────────────────────

    /// Test helper: build a `BoardRow` target with sensible defaults so
    /// each call site doesn't have to spell out every field.
    fn board_target(issue_number: Option<u64>, lifecycle: BoardRowLifecycle) -> ContextMenuTarget {
        ContextMenuTarget::BoardRow {
            issue_number,
            repo_name: Some("repo-a".to_string()),
            lifecycle,
        }
    }

    fn pipeline_target(issue_number: Option<u64>) -> ContextMenuTarget {
        ContextMenuTarget::PipelineRow {
            issue_number,
            repo_name: None,
            lifecycle: PipelineRowLifecycle::Other,
        }
    }

    #[test]
    fn open_context_menu_board_row_seeds_state() {
        // Opening on a Board row produces a non-empty item list and
        // picks the first selectable item as the keyboard focus.
        let mut app = make_app_default();
        let pos = Point::new(10.0, 5.0);
        let opened =
            app.open_context_menu(pos, board_target(Some(42), BoardRowLifecycle::InFlight));
        assert!(opened, "context menu should open for a Board row");
        let state = app.pending_context_menu.expect("state set");
        assert!(!state.items.is_empty());
        // #661: the Board has no direct dispatch; an in-flight row's first item
        // is "Chat about issue" (Send to Pipeline only shows for Backlog rows).
        assert_eq!(
            state.items[state.selected_idx].action_id.as_deref(),
            Some("chat-about-issue"),
        );
        assert!(state.items.iter().any(|it| it.label.contains("#42")));
    }

    #[test]
    fn open_context_menu_includes_refresh_for_pipeline_row() {
        let mut app = make_app_default();
        let opened = app.open_context_menu(Point::new(1.0, 1.0), pipeline_target(None));
        assert!(opened);
        let state = app.pending_context_menu.expect("state set");
        assert!(state.items.iter().any(|it| it.label == "Refresh"));
    }

    #[test]
    fn context_menu_move_selection_skips_separators() {
        let mut app = make_app_default();
        app.open_context_menu(
            Point::new(0.0, 0.0),
            board_target(Some(1), BoardRowLifecycle::InFlight),
        );
        // #661/#815 InFlight layout — Chat about issue / View in Pipeline (disabled)
        // / sep / Copy / sep / Refresh (the Board "Send" is gone).  First selectable
        // item is "chat-about-issue"; moving forward skips the disabled "View in
        // Pipeline" and the separator, landing on "copy-issue-number".
        let state_before = app.pending_context_menu.clone().unwrap();
        app.context_menu_move_selection(1);
        let state_after = app.pending_context_menu.clone().unwrap();
        assert_ne!(state_before.selected_idx, state_after.selected_idx);
        assert_eq!(
            state_after.items[state_after.selected_idx]
                .action_id
                .as_deref(),
            Some("copy-issue-number"),
        );
    }

    #[test]
    fn context_menu_activate_fires_action_and_dismisses() {
        let mut app = make_app_default();
        // #661: the Board "Send" is gone. Use an Unknown/no-issue row whose only
        // item is "Refresh" — activating it fires (kicks a background load) and
        // dismisses the menu without spawning a coordinator command.
        app.open_context_menu(
            Point::new(0.0, 0.0),
            board_target(None, BoardRowLifecycle::Unknown),
        );
        let fired = app.context_menu_activate_selected();
        assert!(fired);
        // Menu dismissed after activating an item.
        assert!(app.pending_context_menu.is_none());
    }

    #[test]
    fn board_menu_offers_send_to_pipeline_never_direct_send() {
        // #661: the Board has NO direct "Send" dispatch — only "Send to Pipeline".
        // A Backlog (untracked open) row offers Send to Pipeline; an already-
        // tracked row (in the Pipeline) offers no Board dispatch at all. The
        // interactive-vs-automated choice lives in the Pipeline menu.
        let app = make_app_default();
        let backlog =
            app.context_menu_items_for_board_row(Some(7), &BoardRowLifecycle::Backlog, None);
        assert!(
            backlog.iter().any(|i| i.label == "Send to Pipeline"),
            "Backlog row must offer Send to Pipeline",
        );
        assert!(
            !backlog.iter().any(|i| i.label == "Send"),
            "Board must never offer the direct Send (#661)",
        );
        let refined =
            app.context_menu_items_for_board_row(Some(7), &BoardRowLifecycle::Refined, None);
        assert!(
            !refined
                .iter()
                .any(|i| i.label == "Send" || i.label == "Send to Pipeline"),
            "an already-tracked row offers no Board dispatch",
        );
    }

    #[test]
    fn context_menu_dismiss_clears_state() {
        let mut app = make_app_default();
        app.open_context_menu(
            Point::new(0.0, 0.0),
            board_target(None, BoardRowLifecycle::Unknown),
        );
        assert!(app.pending_context_menu.is_some());
        app.dismiss_context_menu();
        assert!(app.pending_context_menu.is_none());
    }

