    // ── #676: chat_briefing / troubleshoot_briefing must have safety guardrails

    #[test]
    fn chat_briefing_includes_report_result_prohibition() {
        // #676: the chat briefing must explicitly tell the session not to run
        // `coord report-result --status done` — the hard seam guard backs this
        // up, but the prompt-level prohibition reduces the chance the agent
        // even tries.
        let app = make_pipeline_app();
        let briefing = app.chat_briefing("api", 42);
        assert!(
            briefing.contains("report-result"),
            "briefing must mention report-result prohibition; got: {}",
            &briefing[..briefing.len().min(300)],
        );
        assert!(
            briefing.to_lowercase().contains("do not") || briefing.contains("NOT"),
            "briefing must express the prohibition; got: {}",
            &briefing[..briefing.len().min(300)],
        );
    }

    #[test]
    fn chat_briefing_includes_coord_diagnose_instruction() {
        // #676: for a stalled item the chat session must be directed to run
        // `coord diagnose` first (auto-recovers phantoms, orphaned worktrees).
        let app = make_pipeline_app();
        let briefing = app.chat_briefing("api", 42);
        assert!(
            briefing.contains("coord diagnose"),
            "chat briefing must mention `coord diagnose`; got: {}",
            &briefing[..briefing.len().min(500)],
        );
    }

    #[test]
    fn troubleshoot_briefing_includes_coord_diagnose_as_first_step() {
        // #676: `coord diagnose` must appear as the first step in the
        // troubleshoot briefing so the session doesn't improvise its own
        // diagnostic that may mask the real problem.
        let app = make_pipeline_app();
        let briefing = app.troubleshoot_briefing("api", 42);
        assert!(
            briefing.contains("coord diagnose"),
            "troubleshoot briefing must mention `coord diagnose`; got: {}",
            &briefing[..briefing.len().min(500)],
        );
        // The diagnose step must precede the numbered checklist — i.e., it
        // appears before "1. Test gate".
        let diag_pos = briefing.find("coord diagnose").unwrap();
        let list_pos = briefing.find("1. Test gate").unwrap_or(briefing.len());
        assert!(
            diag_pos < list_pos,
            "`coord diagnose` ({diag_pos}) must precede the numbered checklist ({list_pos})",
        );
    }

    #[test]
    fn troubleshoot_briefing_includes_report_result_prohibition() {
        // #676: the troubleshoot briefing must also prohibit `coord report-result
        // --status done` so the session cannot fake a pipeline advance.
        let app = make_pipeline_app();
        let briefing = app.troubleshoot_briefing("api", 42);
        assert!(
            briefing.contains("report-result"),
            "troubleshoot briefing must mention report-result prohibition; got: {}",
            &briefing[..briefing.len().min(300)],
        );
    }

    // ── #stage-content: per-stage focus + content panel ──────────────────

    #[test]
    fn focus_next_stage_advances_and_wraps() {
        // Since auto-focus now defaults to the first pending stage (Some(0)
        // for a brand-new issue with no assignments), the initial state is
        // Some(0) rather than None.  The advance+wrap behaviour is unchanged.
        let mut app = make_pipeline_app();
        app.active_view = SidebarView::Pipeline;
        app.pipeline_sel = Some(0);
        // Auto-focus puts us on stage 0 (work — the first pending stage).
        assert_eq!(app.pipeline_focused_stage, Some(0));
        app.focus_next_pipeline_stage();
        assert_eq!(app.pipeline_focused_stage, Some(1));
        // Advance to the last stage.
        let stage_count = app
            .pipeline_stage_names_for_issue(&app.pipeline_issues[0])
            .len();
        for _ in 2..stage_count {
            app.focus_next_pipeline_stage();
        }
        // Now at the last stage.  One more wraps back to 0.
        app.focus_next_pipeline_stage();
        assert_eq!(app.pipeline_focused_stage, Some(0));
    }

    #[test]
    fn focus_prev_stage_wraps_from_none_to_last() {
        // Pressing [ before anything is focused should snap to the
        // last stage (so users immediately see the most recent
        // pipeline output rather than the empty Plan stage).
        let mut app = make_pipeline_app();
        app.active_view = SidebarView::Pipeline;
        app.pipeline_sel = Some(0);
        let stage_count = app
            .pipeline_stage_names_for_issue(&app.pipeline_issues[0])
            .len();
        app.focus_prev_pipeline_stage();
        assert_eq!(app.pipeline_focused_stage, Some(stage_count - 1));
    }

    #[test]
    fn stage_content_review_renders_cached_findings() {
        // The DB cache lives on the review-typed assignment as a JSON
        // string.  stage_content_review should parse it and render
        // verdict + body.
        let mut app = make_pipeline_app();
        app.active_view = SidebarView::Pipeline;
        app.pipeline_sel = Some(0);
        let mut review = _stage_assignment("rev1", "review", 200.0, "done");
        review.issue_number = 42;
        review.review_of_assignment_id = Some("w1".to_string());
        review.review_verdict = Some("request-changes".to_string());
        review.review_findings = Some(
            "{\"verdict\":\"request-changes\",\"body\":\"## Issues\\n- Missing test for edge case\"}"
                .to_string(),
        );
        app.data.assignments.push(review);

        let issue = app.pipeline_issues[0].clone();
        let rows = app.stage_content_review(&issue);
        // Should contain the verdict label + the body content.
        let text: String = rows
            .iter()
            .flat_map(|r| r.text.spans.iter().map(|s| s.text.clone()))
            .collect::<Vec<_>>()
            .join(" ");
        assert!(
            text.contains("changes requested") || text.contains("request-changes"),
            "expected verdict in rendered content; got: {text:?}",
        );
        assert!(
            text.contains("Missing test for edge case"),
            "expected body in rendered content; got: {text:?}",
        );
    }

