    // ── #248: parse_coord_review_header ──────────────────────────────────

    #[test]
    fn parse_review_header_full_payload() {
        let body = "<!-- coord:review verdict=request-changes blocking=2 \
                    nonblocking=5 nits=1 reviewer=elitebook \
                    assignment=144ffa027a31 -->\n\n## Review\n\n…";
        let h = parse_coord_review_header(body).expect("header present");
        assert_eq!(h.verdict.as_deref(), Some("request-changes"));
        assert_eq!(h.blocking, Some(2));
        assert_eq!(h.nonblocking, Some(5));
        assert_eq!(h.nits, Some(1));
        assert_eq!(h.reviewer.as_deref(), Some("elitebook"));
        assert_eq!(h.assignment.as_deref(), Some("144ffa027a31"));
    }

    #[test]
    fn parse_review_header_verdict_only() {
        let h = parse_coord_review_header("<!-- coord:review verdict=approve -->")
            .expect("header present");
        assert_eq!(h.verdict.as_deref(), Some("approve"));
        assert_eq!(h.blocking, None);
        assert_eq!(h.reviewer, None);
    }

    #[test]
    fn parse_review_header_returns_none_without_verdict() {
        // A coord:review HTML comment without a verdict token is invalid.
        // Refusing to return a partial header keeps the renderer from
        // showing "verdict: None" badges.
        assert!(parse_coord_review_header("<!-- coord:review reviewer=elitebook -->").is_none());
    }

    #[test]
    fn parse_review_header_returns_none_when_header_missing() {
        assert!(parse_coord_review_header("## Review\n\nLooks fine.").is_none());
    }

    #[test]
    fn parse_review_header_ignores_unknown_tokens() {
        // Future-token tolerance: unknown keys are skipped, never panic.
        let h = parse_coord_review_header("<!-- coord:review verdict=approve cost-usd=0.34 -->")
            .expect("header present");
        assert_eq!(h.verdict.as_deref(), Some("approve"));
    }

    // ── #208: format_cost_usd ────────────────────────────────────────────

    #[test]
    fn format_cost_usd_two_decimal_places() {
        assert_eq!(format_cost_usd(0.34), "$0.34");
        assert_eq!(format_cost_usd(1.50), "$1.50");
        assert_eq!(format_cost_usd(42.00), "$42.00");
    }

    #[test]
    fn format_cost_usd_sub_cent_shows_lt_one_cent() {
        // Half a cent of cost is real work — render it that way instead of
        // rounding to $0.00 which reads as "free".
        assert_eq!(format_cost_usd(0.005), "< $0.01");
        assert_eq!(format_cost_usd(0.001), "< $0.01");
    }

    #[test]
    fn format_cost_usd_zero_or_negative_renders_as_zero() {
        // Defensive: should never see negative, but don't surface a
        // misleading negative dollar amount in the UI.
        assert_eq!(format_cost_usd(0.0), "$0.00");
        assert_eq!(format_cost_usd(-1.0), "$0.00");
    }

    #[test]
    fn parse_review_header_ignores_non_integer_counts() {
        // If the count token can't be parsed (e.g. corrupt header), keep
        // going rather than rejecting the whole header — verdict is still
        // useful on its own.
        let h = parse_coord_review_header("<!-- coord:review verdict=approve blocking=many -->")
            .expect("header present");
        assert_eq!(h.verdict.as_deref(), Some("approve"));
        assert_eq!(h.blocking, None);
    }

    // ── #558: parse_session_summaries_from_comments ───────────────────────────

    /// Build a minimal GitHub-style comment JSON value for test fixtures.
    fn make_comment(
        body: &str,
        created_at: &str,
    ) -> serde_json::Value {
        serde_json::json!({
            "body": body,
            "createdAt": created_at,
        })
    }

    #[test]
    fn parse_iso8601_converts_known_date() {
        // 2024-01-15T12:34:56Z
        // Rough check: result is in Unix-epoch ballpark (~1.7B).
        let ts = parse_iso8601_to_epoch("2024-01-15T12:34:56Z").expect("parsed");
        assert!(ts > 1_700_000_000.0, "should be past Nov 2023: {ts}");
        assert!(ts < 1_800_000_000.0, "should be before 2027: {ts}");
    }

    #[test]
    fn parse_iso8601_returns_none_on_short_string() {
        assert!(parse_iso8601_to_epoch("bad").is_none());
        assert!(parse_iso8601_to_epoch("").is_none());
    }

    #[test]
    fn parse_session_summaries_skips_non_coord_comments() {
        let comments = serde_json::Value::Array(vec![
            make_comment("Just a regular comment without markers.", "2024-01-01T00:00:00Z"),
            make_comment("<!-- some-other-tool: data -->", "2024-01-01T01:00:00Z"),
        ]);
        let result = parse_session_summaries_from_comments(&comments, &[]);
        assert!(result.is_empty(), "no coord markers → empty result");
    }

    #[test]
    fn parse_session_summaries_parses_completion_comment() {
        // Mirrors what `format_completion` in coord/comments.py produces.
        let body = "## Coordinator: Assignment Complete\n\
            <!-- coord:event=completion assignment=abc123 machine=precision repo=myrepo issue=42 exit_code=0 -->\n\
            **Machine:** precision\n\
            **Status:** done\n\
            **Exit code:** 0\n\
            **Duration:** 5m 30s\n\
            \n\
            ### Summary\n\
            Migrated the TUI to use the new primitive.\n";

        let comments = serde_json::Value::Array(vec![
            make_comment(body, "2024-06-01T10:00:00Z"),
        ]);
        let result = parse_session_summaries_from_comments(&comments, &[]);
        assert_eq!(result.len(), 1);
        let s = &result[0];
        assert_eq!(s.assignment_id, "abc123");
        assert_eq!(s.machine, "precision");
        assert_eq!(s.status, "done");
        assert!(s.verdict.is_none());
        assert_eq!(s.summary_text, "Migrated the TUI to use the new primitive.");
    }

