    // ── #1022 fix iteration 1: resolve_smoke_test_verdict unit tests ────────────

    /// #1022: The Test row's verdict/reason must be sourced from the linked
    /// work assignment (`review_of_assignment_id`), not the smoke row itself.
    #[test]
    fn resolve_smoke_test_verdict_prefers_linked_work_assignment() {
        let mut work = make_assignment_typed("done", 1, "repo-a", Some("work"));
        work.id = "w1".to_string();
        work.test_state = Some("failed".to_string());
        work.test_reason = Some("boom".to_string());

        let mut smoke = make_assignment_typed("done", 1, "repo-a", Some("smoke"));
        smoke.id = "s1".to_string();
        smoke.review_of_assignment_id = Some("w1".to_string());

        let assignments: Vec<&Assignment> = vec![&work, &smoke];
        let (verdict, reason) = resolve_smoke_test_verdict(&smoke, &assignments);
        assert_eq!(verdict, Some("failed"));
        assert_eq!(reason, Some("boom"));
    }

    /// #1022: When the link is absent (defensive: rows predating it), fall
    /// back to the most-recently-dispatched work-like assignment that has a
    /// recorded verdict.
    #[test]
    fn resolve_smoke_test_verdict_falls_back_to_latest_work_when_unlinked() {
        let mut work = make_assignment_typed("done", 1, "repo-a", Some("work"));
        work.id = "w1".to_string();
        work.test_state = Some("passed".to_string());

        let mut smoke = make_assignment_typed("done", 1, "repo-a", Some("smoke"));
        smoke.id = "s1".to_string();
        // No review_of_assignment_id set — exercises the defensive fallback.

        let assignments: Vec<&Assignment> = vec![&work, &smoke];
        let (verdict, _) = resolve_smoke_test_verdict(&smoke, &assignments);
        assert_eq!(verdict, Some("passed"));
    }

    /// #1022: When no verdict is recorded anywhere, fall back to the smoke
    /// row's own (empty) fields rather than panicking or fabricating one.
    #[test]
    fn resolve_smoke_test_verdict_falls_back_to_own_fields_when_no_verdict_anywhere() {
        let work = make_assignment_typed("done", 1, "repo-a", Some("work"));
        let smoke = make_assignment_typed("done", 1, "repo-a", Some("smoke"));

        let assignments: Vec<&Assignment> = vec![&work, &smoke];
        let (verdict, reason) = resolve_smoke_test_verdict(&smoke, &assignments);
        assert_eq!(verdict, None);
        assert_eq!(reason, None);
    }

    /// #1022 fix iter 2 (smoke-round-2 bug): a smoke row whose linked work has
    /// NOT been verdicted yet (Test still running) must show its OWN status —
    /// NOT resurrect an older sibling's stale verdict via the tier-2 scan.
    ///
    /// Repro: an in-progress Test on the current work iteration was showing
    /// `failed ✗` with the write-up from a PRIOR, unrelated smoke round because
    /// tier 2 unconditionally scanned every work-like assignment for any
    /// recorded verdict — even when the row's own link was valid, just pending.
    #[test]
    fn resolve_smoke_test_verdict_linked_but_unverdicted_uses_own_status_not_stale_sibling() {
        // Older iteration: a work assignment that DID get a failed verdict.
        let mut old_work = make_assignment_typed("done", 1, "repo-a", Some("work"));
        old_work.id = "w_old".to_string();
        old_work.test_state = Some("failed".to_string());
        old_work.test_reason = Some("stale story from a prior round".to_string());

        // Current iteration: work assignment, no verdict recorded yet.
        // Higher issue number ⇒ later dispatched_at ⇒ would win the tier-2 scan
        // IF it had a verdict — but it doesn't, which is the whole point.
        let mut new_work = make_assignment_typed("done", 2, "repo-a", Some("work"));
        new_work.id = "w_new".to_string();
        // new_work.test_state stays None — the Test is still in progress.

        // The smoke row links to the CURRENT work and is itself still running.
        let mut smoke = make_assignment_typed("running", 2, "repo-a", Some("smoke"));
        smoke.id = "s_new".to_string();
        smoke.review_of_assignment_id = Some("w_new".to_string());
        // smoke.test_state stays None — no verdict borrowed, no own verdict.

        let assignments: Vec<&Assignment> = vec![&old_work, &new_work, &smoke];
        let (verdict, reason) = resolve_smoke_test_verdict(&smoke, &assignments);
        assert_eq!(
            verdict, None,
            "a linked-but-unverdicted Test must NOT borrow a sibling's verdict"
        );
        assert_eq!(
            reason, None,
            "a linked-but-unverdicted Test must NOT show a prior round's reason"
        );
    }

    /// #1022 fix iter 2: an ORPHANED link (review_of_assignment_id points to an
    /// assignment that no longer exists — a legacy/deleted row) still falls
    /// through to the tier-2 defensive scan. Only a VALID-but-pending link
    /// short-circuits to tier 3.
    #[test]
    fn resolve_smoke_test_verdict_orphaned_link_falls_through_to_scan() {
        let mut work = make_assignment_typed("done", 1, "repo-a", Some("work"));
        work.id = "w1".to_string();
        work.test_state = Some("passed".to_string());

        let mut smoke = make_assignment_typed("done", 1, "repo-a", Some("smoke"));
        smoke.id = "s1".to_string();
        // Points at an id that isn't in `assignments` — orphaned link.
        smoke.review_of_assignment_id = Some("w_missing".to_string());

        let assignments: Vec<&Assignment> = vec![&work, &smoke];
        let (verdict, _) = resolve_smoke_test_verdict(&smoke, &assignments);
        assert_eq!(
            verdict,
            Some("passed"),
            "an orphaned link must fall through to the tier-2 scan"
        );
    }

    // ── #1022: Unit tests for assignment_status_badge flat-row rule ──────────────

    /// #1022: Work/fix rows must show only their own completion status — no
    /// test_state overlay.  The test verdict belongs to the Test row.
    #[test]
    fn assignment_status_badge_work_shows_only_completion_status() {
        // Work done with test_state=passed — must NOT show "done · Test ✓".
        let mut work_passed = make_assignment_typed("done", 10, "repo-a", Some("work"));
        work_passed.test_state = Some("passed".to_string());
        let (text, _) = assignment_status_badge(&work_passed);
        assert_eq!(text, "done", "work+test=passed must show 'done', not composite");

        // Work done with test_state=failed — must NOT show "done · Test ✗".
        let mut work_failed = make_assignment_typed("done", 11, "repo-a", Some("work"));
        work_failed.test_state = Some("failed".to_string());
        let (text, _) = assignment_status_badge(&work_failed);
        assert_eq!(text, "done", "work+test=failed must show 'done', not composite");

        // Work done with test_state=skipped — must NOT show "done · Test ↷".
        let mut work_skipped = make_assignment_typed("done", 12, "repo-a", Some("work"));
        work_skipped.test_state = Some("skipped".to_string());
        let (text, _) = assignment_status_badge(&work_skipped);
        assert_eq!(text, "done", "work+test=skipped must show 'done', not composite");

        // Work running: no test_state yet.
        let work_running = make_assignment_typed("running", 13, "repo-a", Some("work"));
        let (text, _) = assignment_status_badge(&work_running);
        assert_eq!(text, "running…");

        // Work failed (hard failure).
        let work_fail = make_assignment_typed("failed", 14, "repo-a", Some("work"));
        let (text, _) = assignment_status_badge(&work_fail);
        assert_eq!(text, "failed");
    }

    /// #1022: Smoke (Test) rows must show the test_state as their own badge.
    #[test]
    fn assignment_status_badge_smoke_shows_test_verdict() {
        // Smoke passed.
        let mut smoke_passed = make_assignment_typed("done", 20, "repo-a", Some("smoke"));
        smoke_passed.test_state = Some("passed".to_string());
        let (text, _) = assignment_status_badge(&smoke_passed);
        assert_eq!(text, "passed ✓", "smoke+passed must show 'passed ✓'");

        // Smoke failed.
        let mut smoke_failed = make_assignment_typed("done", 21, "repo-a", Some("smoke"));
        smoke_failed.test_state = Some("failed".to_string());
        let (text, _) = assignment_status_badge(&smoke_failed);
        assert_eq!(text, "failed ✗", "smoke+failed must show 'failed ✗'");

        // Smoke skipped.
        let mut smoke_skipped = make_assignment_typed("done", 22, "repo-a", Some("smoke"));
        smoke_skipped.test_state = Some("skipped".to_string());
        let (text, _) = assignment_status_badge(&smoke_skipped);
        assert_eq!(text, "skipped ↷", "smoke+skipped must show 'skipped ↷'");

        // Smoke running (no verdict yet).
        let smoke_running = make_assignment_typed("running", 23, "repo-a", Some("smoke"));
        let (text, _) = assignment_status_badge(&smoke_running);
        assert_eq!(text, "testing…", "smoke running must show 'testing…'");

        // Smoke done but no test_state (incomplete verdict).
        let smoke_done = make_assignment_typed("done", 24, "repo-a", Some("smoke"));
        let (text, _) = assignment_status_badge(&smoke_done);
        assert_eq!(text, "done", "smoke done without verdict must show 'done'");
    }

