    /// #1197: `resolve_nested_child_index` must resolve a nested-child row
    /// to the CHILD's own `pipeline_issues` index — never silently fall
    /// back to the parent epic's index — so a click/nav on a nested row
    /// acts on the right issue.
    #[test]
    fn resolve_nested_child_index_finds_child_own_pipeline_issues_index() {
        let data = BoardData {
            epic_children: vec![EpicChildren {
                repo_name: "api".to_string(),
                tracking_issue: 100,
                children: vec![
                    EpicChild { number: 101, state: "open".to_string() },
                    EpicChild { number: 102, state: "closed".to_string() },
                ],
            }],
            ..BoardData::default()
        };
        let mut app = make_test_app(data);
        app.pipeline_issues = vec![
            pipeline_issue_stub(100, "acme/api", "api"), // epic, idx 0
            // #101 is independently tracked too (e.g. it also carries a
            // tracked label) — idx 1.
            pipeline_issue_stub(101, "acme/api", "api"),
        ];

        // child_pos 0 → #101, which IS in pipeline_issues → its own idx 1,
        // not the epic's idx 0.
        assert_eq!(app.resolve_nested_child_index(0, 0, None), Some(1));
        // child_pos 1 → #102, which is NOT independently tracked in
        // pipeline_issues → None (nested-display-only row), never silently
        // the parent epic's idx 0.
        assert_eq!(app.resolve_nested_child_index(0, 1, None), None);
        // parent_idx pointing at a non-epic issue (#101 has no children of
        // its own) → None.
        assert_eq!(app.resolve_nested_child_index(1, 0, None), None);
    }

    /// #1199 fix (review-reported regression): a regular issue nested under
    /// an epic that does NOT independently carry a tracked label (only its
    /// parent epic does) was previously absent from `pipeline_issues`
    /// entirely, so `resolve_nested_child_index` could never resolve a click
    /// on its nested row — `pipeline_sel` stuck at `None`, no
    /// Work/Test/Review/Merge lane rendered ("blank"), and the Issue tab fell
    /// back to "No issue selected". `pipeline_issues_from_cache` must
    /// backfill such a child from `data.open_issues` so it's independently
    /// selectable exactly like a directly-tracked sibling.
    #[test]
    fn pipeline_issues_from_cache_backfills_untracked_epic_child() {
        let data = BoardData {
            pipeline_tracked_labels: vec!["coord".to_string()],
            pipeline_repos: vec![("api".to_string(), "acme/api".to_string())],
            pipeline_default_gates: vec!["test".to_string(), "review".to_string(), "merge".to_string()],
            open_issues: vec![
                OpenIssue {
                    repo_name: "api".to_string(),
                    number: 100,
                    title: "Epic tracker".to_string(),
                    body: String::new(),
                    state: "open".to_string(),
                    labels: vec!["coord".to_string(), "epic".to_string()],
                    milestone_number: Some(1),
                    milestone_title: Some("v1.0".to_string()),
                },
                // #102 carries NO tracked label of its own — only its parent
                // epic #100 does. This is the exact shape of the reported
                // regression (siblings #1031/#1032 blank while #1033/#1097,
                // independently tracked, rendered fine).
                OpenIssue {
                    repo_name: "api".to_string(),
                    number: 102,
                    title: "Untracked child".to_string(),
                    body: String::new(),
                    state: "open".to_string(),
                    labels: vec![],
                    milestone_number: Some(1),
                    milestone_title: Some("v1.0".to_string()),
                },
            ],
            epic_children: vec![EpicChildren {
                repo_name: "api".to_string(),
                tracking_issue: 100,
                children: vec![EpicChild { number: 102, state: "open".to_string() }],
            }],
            ..BoardData::default()
        };
        let mut app = make_test_app(data);
        let issues = app.pipeline_issues_from_cache();

        assert!(
            issues.iter().any(|i| i.number == 100),
            "tracked epic #100 must still be present",
        );
        let child = issues.iter().find(|i| i.number == 102).expect(
            "untracked epic child #102 must be backfilled into pipeline_issues, \
             or its nested row can never resolve a selection",
        );
        assert_eq!(child.coord_repo.as_deref(), Some("api"));
        assert_eq!(child.title, "Untracked child");
        assert!(
            child.matched_labels.is_empty(),
            "the child carries no tracked label of its own — matched_labels stays empty",
        );

        // End-to-end: once backfilled, the nested-child row must resolve to
        // the child's OWN index (never silently falling back to the epic's).
        app.pipeline_issues = issues;
        let epic_idx = app
            .pipeline_issues
            .iter()
            .position(|i| i.number == 100)
            .unwrap();
        let child_idx = app
            .pipeline_issues
            .iter()
            .position(|i| i.number == 102)
            .unwrap();
        assert_eq!(app.resolve_nested_child_index(epic_idx, 0, None), Some(child_idx));

        // And the child's own pipeline lane must be the ordinary per-issue
        // lane (Work/Test/Review — "merge" is retired from this per-issue
        // strip per #738, living solely in the Merge Queue panel), NOT the
        // epic gate lane, and NOT suppressed (`build_pipeline_widget`
        // returning `None`, which is the literal "blank lane" the review
        // reported).
        app.pipeline_sel = Some(child_idx);
        let view = app
            .build_pipeline_widget()
            .expect("a regular nested child must render its own pipeline lane, not blank");
        assert_eq!(
            view.stages.iter().map(|s| s.label.as_str()).collect::<Vec<_>>(),
            vec!["Work", "Test", "Review"],
        );
    }

    /// A child NOT listed under any tracked epic (no matching
    /// `EpicChildren.tracking_issue` in `pipeline_issues`) must NOT be
    /// backfilled — only children of an epic that's itself in the Pipeline
    /// are in scope.
    #[test]
    fn pipeline_issues_from_cache_skips_children_of_untracked_epic() {
        let data = BoardData {
            pipeline_tracked_labels: vec!["coord".to_string()],
            pipeline_repos: vec![("api".to_string(), "acme/api".to_string())],
            open_issues: vec![OpenIssue {
                repo_name: "api".to_string(),
                number: 202,
                title: "Orphan child".to_string(),
                body: String::new(),
                state: "open".to_string(),
                labels: vec![],
                milestone_number: None,
                milestone_title: None,
            }],
            // tracking_issue 999 is NOT itself a tracked issue anywhere.
            epic_children: vec![EpicChildren {
                repo_name: "api".to_string(),
                tracking_issue: 999,
                children: vec![EpicChild { number: 202, state: "open".to_string() }],
            }],
            ..BoardData::default()
        };
        let app = make_test_app(data);
        let issues = app.pipeline_issues_from_cache();
        assert!(
            issues.iter().all(|i| i.number != 202),
            "a child of an untracked epic must not be backfilled",
        );
    }

    /// #1199 fix (label "#1031 #1031"): a child that has aged out of the
    /// `open_issues` cache has no title anywhere — `build_dag_nodes` falls
    /// back to `title = "#N"`, which the nested row previously rendered
    /// verbatim after its own `#N` column ("#1031 #1031"). The row must show
    /// a muted placeholder instead, keeping a single `#N`.
    #[test]
    fn epic_child_row_replaces_number_fallback_title_with_placeholder() {
        let app = make_test_app(BoardData::default());
        let child = EpicChildRow {
            number: 1031,
            // Exactly what build_dag_nodes emits when the issue is absent.
            title: "#1031".to_string(),
            state: NodeState::Done,
        };
        let row = app.epic_child_tree_row(&[0u16, 0u16], 3, 0, &child);
        let joined: String = row.text.spans.iter().map(|s| s.text.as_str()).collect();
        assert!(joined.contains("#1031"), "keeps the #N identity column");
        assert_eq!(
            joined.matches("1031").count(),
            1,
            "the issue number must NOT be duplicated as the title (the reported '#1031 #1031')",
        );
        assert!(
            joined.contains("(details not cached)"),
            "an uncached child shows a muted placeholder, got {joined:?}",
        );
    }

    /// The placeholder must NOT clobber a child that DOES have a real title
    /// (the #1097 case — cached, so `build_dag_nodes` found its title).
    #[test]
    fn epic_child_row_keeps_a_real_title() {
        let app = make_test_app(BoardData::default());
        let child = EpicChildRow {
            number: 1097,
            title: "Live/Idle sessions".to_string(),
            state: NodeState::Done,
        };
        let row = app.epic_child_tree_row(&[0u16, 0u16], 3, 0, &child);
        let joined: String = row.text.spans.iter().map(|s| s.text.as_str()).collect();
        assert!(joined.contains("Live/Idle sessions"), "got {joined:?}");
        assert!(!joined.contains("(details not cached)"));
    }

    /// #1199 fix (selection snaps to the epic on refresh): an OPEN epic
    /// (#100) with a tracked open child (#102, Ready) — the child renders
    /// NESTED under the epic. Selecting the child then hitting the
    /// periodic refresh (`rebuild_pipeline_sidebar`) must KEEP the child
    /// selected, never snapping the selection to the epic parent (which
    /// would replace the child's Work/Test/Review lane with the epic's
    /// Gate A→D lane).
    ///
    /// #1281 note: the pre-#1281 fixture used a CLOSED child (#102 with
    /// `state="closed"`) — which under #1281 no longer nests under the
    /// epic's In-progress → Idle instance and so gives the test no row to
    /// select. The child is now open+Ready so the nested row still
    /// renders and the #1199 selection-preservation invariant stays
    /// covered.
    #[test]
    fn nested_child_selection_survives_refresh_and_does_not_snap_to_epic() {
        let data = BoardData {
            pipeline_tracked_labels: vec!["coord".to_string()],
            pipeline_repos: vec![("api".to_string(), "acme/api".to_string())],
            open_issues: vec![
                OpenIssue {
                    repo_name: "api".to_string(),
                    number: 100,
                    title: "Epic tracker".to_string(),
                    body: String::new(),
                    state: "open".to_string(),
                    labels: vec!["coord".to_string(), "epic".to_string()],
                    milestone_number: None,
                    milestone_title: None,
                },
                // Open + independently tracked child — Ready, so the
                // nested row survives the #1281 In-progress filter.
                OpenIssue {
                    repo_name: "api".to_string(),
                    number: 102,
                    title: "Open child".to_string(),
                    body: String::new(),
                    state: "open".to_string(),
                    labels: vec!["coord".to_string()],
                    milestone_number: None,
                    milestone_title: None,
                },
            ],
            epic_children: vec![EpicChildren {
                repo_name: "api".to_string(),
                tracking_issue: 100,
                children: vec![EpicChild { number: 102, state: "open".to_string() }],
            }],
            ..BoardData::default()
        };
        let mut app = make_test_app(data);
        app.pipeline_issues = app.pipeline_issues_from_cache();
        let child_idx = app.pipeline_issues.iter().position(|i| i.number == 102).unwrap();
        let epic_idx = app.pipeline_issues.iter().position(|i| i.number == 100).unwrap();
        app.rebuild_pipeline_sidebar(None);

        // Select the nested child row.
        let (section, path, sel) = app
            .locate_pipeline_selection("acme/api", 102)
            .expect("the nested child must be locatable");
        assert!(path.len() >= 4, "must be a nested path (deeper than a top-level row): {path:?}");
        assert_eq!(sel, Some(child_idx), "resolves to the child's own index, not the epic's");
        app.pipeline_sidebar.set_active_section(Some(section));
        app.pipeline_sidebar.set_selected_path(section, Some(path));
        app.pipeline_sel = app.selected_pipeline_index();
        assert_eq!(app.pipeline_sel, Some(child_idx), "sanity: the child is selected");

        // The periodic-refresh path: capture → rebuild → must PRESERVE the child.
        let prev = app.capture_pipeline_selection_id();
        assert_eq!(prev, Some(("acme/api".to_string(), 102)));
        app.rebuild_pipeline_sidebar(prev);
        assert_eq!(
            app.pipeline_sel,
            Some(child_idx),
            "the nested child selection must survive the refresh",
        );
        assert_ne!(app.pipeline_sel, Some(epic_idx), "must not snap to the epic parent");
    }

    /// #1281 supersedes the pre-#1281 #1199 concern for aged-out children:
    /// a child ABSENT from `open_issues` (aged out of the sync cache, the
    /// #1031/#1032/#1033 shape) is presumed closed by
    /// `milestone_dag::build_dag_nodes` — its [`NodeState`] resolves to
    /// [`NodeState::Done`] via the aged-out ⇒ terminal heuristic. Under
    /// #1281 a Done child does not nest under its epic's In-progress →
    /// Idle instance, so `locate_pipeline_selection` legitimately returns
    /// `None`: there is no rendered nested row to select, and hence no
    /// "select then refresh must not snap to the epic" invariant to test.
    /// The child stays out of the Pipeline until the epic itself closes.
    ///
    /// This test documents that new #1281 boundary directly. Callers that
    /// still care about the #1199 "must not snap to epic" invariant have
    /// coverage on the previous test, which now uses a Ready (not Done)
    /// child so the nested row still renders.
    #[test]
    fn absent_nested_child_is_hidden_under_1281_and_not_locatable() {
        let data = BoardData {
            pipeline_tracked_labels: vec!["coord".to_string()],
            pipeline_repos: vec![("api".to_string(), "acme/api".to_string())],
            open_issues: vec![OpenIssue {
                repo_name: "api".to_string(),
                number: 100,
                title: "Epic tracker".to_string(),
                body: String::new(),
                state: "open".to_string(),
                labels: vec!["coord".to_string(), "epic".to_string()],
                milestone_number: None,
                milestone_title: None,
            }],
            // #103 has no cached OpenIssue at all → `build_dag_nodes`
            // resolves it to `NodeState::Done` via the aged-out ⇒ terminal
            // heuristic, so #1281 filters it out of the epic's In-progress
            // → Idle instance's nested list.
            epic_children: vec![EpicChildren {
                repo_name: "api".to_string(),
                tracking_issue: 100,
                children: vec![EpicChild { number: 103, state: "open".to_string() }],
            }],
            ..BoardData::default()
        };
        let mut app = make_test_app(data);
        app.pipeline_issues = app.pipeline_issues_from_cache();
        assert!(
            app.pipeline_issues.iter().all(|i| i.number != 103),
            "precondition: the absent child is NOT in pipeline_issues",
        );
        app.rebuild_pipeline_sidebar(None);

        // #1281: the aged-out (Done-presumed) nested child no longer
        // renders under In-progress → Idle, so `locate_pipeline_selection`
        // returns None — the child simply isn't on the screen for the user
        // to select in the first place.
        assert!(
            app.locate_pipeline_selection("acme/api", 103).is_none(),
            "an aged-out Done child must not be locatable under #1281 — it renders nowhere \
             while the epic itself is still open",
        );
    }

    #[test]
    fn pipeline_milestone_collapse_state_persists_across_rebuild() {
        // Collapsing a milestone sub-header must survive the next rebuild_pipeline_sidebar.
        let mut app = make_pipeline_milestone_app();
        // The new section is section index 1 (0 = filter).
        // Manually set a milestone collapsed in pipeline_milestone_expanded.
        // Key: (lc_key="new", repo="api", milestone="1").
        // pipeline_repo_key() returns coord_repo ("api") not repo_slug ("acme/api").
        app.pipeline_milestone_expanded
            .insert(("new".to_string(), "api".to_string(), "1".to_string()), false);

        // Rebuild — the collapsed state must be re-applied.
        app.rebuild_pipeline_sidebar(None);

        // The state must still be false (collapsed) in the map.
        let collapsed = app
            .pipeline_milestone_expanded
            .get(&("new".to_string(), "api".to_string(), "1".to_string()))
            .copied()
            .unwrap_or(true);
        assert!(
            !collapsed,
            "milestone collapse state must persist across rebuild",
        );
    }

