    /// `build_kanban_model` must route issues to the correct Kanban columns
    /// based on `lifecycle_section()`.
    ///
    /// Lifecycle rules (relevant subset):
    /// - Only workable assignment types (`work`, `review`, `smoke`, `conflict-fix`,
    ///   `fix-N`) count for routing; non-workable types (`refinement`,
    ///   `test-chat`, `new-issue-chat`) leave the issue in Backlog.
    /// - An issue with a running workable assignment AND `is_closed = false`
    ///   lands in In Flight.
    /// - An issue with `is_closed = true` lands in Completed.
    #[test]
    fn build_kanban_model_buckets_issues_correctly() {
        // Backlog: only a non-workable (refinement) assignment — does NOT drag
        // the issue into In-flight (is_workable_type("refinement") == false).
        let backlog_a = make_assignment_typed("pending", 1, "repo-a", Some("refinement"));
        // In-flight: running workable assignment on an open issue.
        let inflight_a = make_assignment_typed("running", 2, "repo-a", Some("work"));
        // Completed: done workable assignment; issue will be marked closed below.
        let completed_a = make_assignment_typed("done", 3, "repo-a", Some("work"));

        let assignments = vec![backlog_a, inflight_a, completed_a];
        let mut app = make_app_with_assignments(assignments);

        // Mark issue 3 as closed in the cache so lifecycle_section → "completed".
        for (_, groups) in &mut app.board_issues_cache {
            for g in groups.iter_mut() {
                if g.issue_number == 3 {
                    g.is_closed = true;
                }
            }
        }

        let model = app.build_kanban_model();
        assert_eq!(model.columns.len(), 3, "model must have 3 columns");

        let backlog_col = model.columns.iter().find(|c| c.title == "Backlog").unwrap();
        let inflight_col = model.columns.iter().find(|c| c.title == "In Flight").unwrap();
        let completed_col = model.columns.iter().find(|c| c.title == "Completed").unwrap();

        assert_eq!(backlog_col.cards.len(), 1,
            "backlog column must contain the refinement-only issue (non-workable type)");
        assert_eq!(inflight_col.cards.len(), 1,
            "in-flight column must contain the running work issue");
        assert_eq!(completed_col.cards.len(), 1,
            "completed column must contain the closed+done issue");
    }

    /// `build_kanban_model` card ids must follow the `card:<repo>:<issue>` format
    /// so that `kanban_open_card` can parse them correctly.
    #[test]
    fn build_kanban_model_card_id_format() {
        let a = make_assignment_typed("running", 42, "my-repo", Some("work"));
        let mut app = make_app_with_assignments(vec![a]);
        app.rebuild_board_sidebar();
        let model = app.build_kanban_model();
        let all_cards: Vec<_> = model.columns.iter().flat_map(|c| c.cards.iter()).collect();
        assert!(!all_cards.is_empty(), "must have at least one card");
        for card in &all_cards {
            let s = card.id.as_str();
            assert!(s.starts_with("card:"),
                "card id must start with 'card:'; got: {s}");
            let parts: Vec<&str> = s.splitn(3, ':').collect();
            assert_eq!(parts.len(), 3,
                "card id must have 3 colon-separated parts; got: {s}");
            // Third part must parse as a number.
            parts[2].parse::<u64>()
                .unwrap_or_else(|_| panic!("third part of card id must be u64; got: {s}"));
        }
    }

    /// After `rebuild_board_sidebar`, per-column vertical scroll offsets
    /// must survive the rebuild unchanged (not reset to 0).
    #[test]
    fn rebuild_board_sidebar_preserves_kanban_column_scroll() {
        let a1 = make_assignment_typed("running", 10, "repo-a", Some("work"));
        let a2 = make_assignment_typed("running", 20, "repo-a", Some("work"));
        let mut app = make_app_with_assignments(vec![a1, a2]);
        app.rebuild_board_sidebar();

        // Simulate the user having scrolled the In Flight column down.
        let inflight_idx = app.kanban_model.columns.iter()
            .position(|c| c.title == "In Flight")
            .unwrap();
        app.kanban_model.columns[inflight_idx].scroll_offset = 1;

        // A background data refresh triggers rebuild.
        app.rebuild_board_sidebar();

        assert_eq!(
            app.kanban_model.columns[inflight_idx].scroll_offset, 1,
            "per-column scroll offset must survive rebuild_board_sidebar"
        );
    }

    // ─── TuiDriver black-box screen tests (#690 / #691) ───────────────────────
    //
    // These tests drive the full CoordApp → ShellAdapter → dispatch_event →
    // render_frame pipeline via quadraui's `driver_with_shell`, which uses an
    // in-memory `TestBackend` instead of a live terminal.  No network, no
    // daemon, no TTY — deterministic `cargo test`-native.
    //
    // The API:
    //   `find("text")` → `Option<(f32,f32)>` — cell coords of a painted string.
    //   `click(x,y)`                          — routes through hit-test → handle.
    //   `press_named(NamedKey::...)`           — keyboard event round-trip.
    //   `type_char(c)`                         — single character key press.
    //   `screen_contains(needle)` / `screen()` — inspect the rendered buffer.

    /// Test 1 (most important — exercises the `issue_body_list` render path
    /// that #669 touches):
    ///
    /// Board view + Issue detail tab + a synced `open_issues` row → the issue
    /// body text must appear on screen.  The setup pre-selects the sidebar row
    /// and switches the detail tab programmatically (both are private state
    /// accessible from the in-crate test module) so the test stays focused on
    /// the render path rather than on sidebar-navigation sequencing.
    #[test]
    fn tuidriver_board_issue_body_renders() {
        use quadraui::tui::testing::driver_with_shell;

        const BODY: &str =
            "This fix addresses a critical rendering bug visible in the dashboard panel";

        // App with one running issue and a synced open_issues row bearing the body.
        let assignments = vec![make_assignment_typed("running", 10, "repo-a", Some("work"))];
        let mut app = make_app_with_assignments(assignments);
        app.data.open_issues.push(OpenIssue {
            repo_name: "repo-a".to_string(),
            number: 10,
            title: "Fix dashboard rendering".to_string(),
            body: BODY.to_string(),
            state: "open".to_string(),
            labels: Vec::new(),
            milestone_number: None,
            milestone_title: None,
        });

        // Pre-select the issue in the sidebar (milestone 0, issue 0 within that
        // milestone — matches the single "No milestone" group rebuild_board_sidebar
        // creates for a single running issue).  After rebuild_board_sidebar the
        // active section is already 1 (repo-a); we just need the row path.
        app.board_sidebar.set_selected_path(1, Some(vec![0, 0]));
        // Switch to the Issue detail tab so render_content draws board_issue_body_list.
        app.board_detail_tab = BoardDetailTab::Issue;

        // Wrap in the full ShellAdapter → TestBackend driver.
        let driver = driver_with_shell(app, CoordApp::shell_config(), 120, 40);

        assert!(
            driver.screen_contains(BODY),
            "Issue body must render on the Board > Issue tab:\n{}",
            driver.screen()
        );
    }

    /// Test 2 — list rendering:
    ///
    /// An issue with a known title must appear in the Board sidebar tree.
    /// Verifies that `rebuild_board_sidebar` + `draw_sidebar_panel` + the
    /// initial `render_frame` call all wire together correctly end-to-end.
    #[test]
    fn tuidriver_board_sidebar_shows_issue_title() {
        use quadraui::tui::testing::driver_with_shell;

        // make_assignment_typed sets issue_title = "Issue <N>".
        let assignments = vec![make_assignment_typed("running", 42, "test-repo", Some("work"))];
        let app = make_app_with_assignments(assignments);

        let driver = driver_with_shell(app, CoordApp::shell_config(), 120, 40);

        // The sidebar tree row is formatted as "#42   Issue 42" (issue number
        // left-padded to 5 chars + truncated title).  Either fragment is enough.
        assert!(
            driver.screen_contains("Issue 42") || driver.screen_contains("#42"),
            "Issue title / number must appear in the board sidebar:\n{}",
            driver.screen()
        );
    }

    /// Test 3 — event round-trip:
    ///
    /// Clicking the "Issue" tab in the Board detail panel (located via `find`)
    /// must switch the active tab and re-render the content area.  This
    /// exercises the full `UiEvent::MouseDown` → `handle` → `Reaction::Redraw`
    /// → `render_frame` path — the same path that every real user click takes.
    #[test]
    fn tuidriver_clicking_issue_tab_changes_screen() {
        use quadraui::tui::testing::driver_with_shell;

        // App with one running issue and a synced body, starting on the default
        // "Board" detail tab (no pre-selection needed — we just want to confirm
        // that a click on "Issue" triggers a visible change).
        let assignments = vec![make_assignment_typed("running", 7, "click-repo", Some("work"))];
        let mut app = make_app_with_assignments(assignments);
        app.data.open_issues.push(OpenIssue {
            repo_name: "click-repo".to_string(),
            number: 7,
            title: "click round-trip test".to_string(),
            body: "Event round-trip verified via TuiDriver click".to_string(),
            state: "open".to_string(),
            labels: Vec::new(),
            milestone_number: None,
            milestone_title: None,
        });
        // Pre-select the issue row so the Issue tab has content to switch to.
        app.board_sidebar.set_selected_path(1, Some(vec![0, 0]));

        let mut driver = driver_with_shell(app, CoordApp::shell_config(), 120, 40);

        let screen_before = driver.screen();

        // Locate the "Issue" tab label in the tab bar and click it.
        // `find` returns None if the label isn't painted — fail clearly.
        let (x, y) = driver
            .find("Issue")
            .unwrap_or_else(|| panic!("'Issue' tab label not found on initial render:\n{screen_before}"));
        driver.click(x, y);

        let screen_after = driver.screen();
        assert_ne!(
            screen_before, screen_after,
            "clicking 'Issue' tab must trigger a re-render that changes the screen"
        );
    }

    // ── #717: a done work row un-greys the interactive Testing action ─────────

    /// #717 gate (builder-level — the precise regression guard): the interactive
    /// "Testing" launcher is enabled only when there is a completed (`done`)
    /// work row WITH a branch.  Before #717 an interactive session that pushed
    /// its branch could finalize as `failed`, leaving Testing greyed; this
    /// asserts the failed→done transition flips the gate.
    #[test]
    fn context_menu_testing_enabled_only_for_done_work_with_branch() {
        fn testing_disabled(app: &CoordApp) -> bool {
            let items = app
                .context_menu_items_for_pipeline_row(Some(42), &PipelineRowLifecycle::Other, None);
            let parent = items
                .iter()
                .find(|i| i.label == "Start (interactive)")
                .expect("Start (interactive) submenu must exist");
            let children = parent.submenu.as_ref().expect("interactive submenu");
            children
                .iter()
                .find(|i| i.action_id.as_deref() == Some("start-testing-interactive"))
                .expect("Testing item must exist")
                .disabled
        }

        let mut app = make_pipeline_app_with_test_gate();
        app.active_view = SidebarView::Pipeline;
        app.pipeline_sel = Some(0);

        // Pre-#717 bug state: the work pushed a branch but the row is `failed`.
        let mut row = _work_assignment("w1", 100.0, "failed", None);
        row.branch = Some("issue-42-add-cool-thing".to_string());
        app.data.assignments.push(row);
        assert!(
            testing_disabled(&app),
            "a failed work row must leave the interactive Testing action greyed"
        );

        // Post-#717: finalize records `done` → Testing must be enabled.
        app.data.assignments[0].status = "done".into();
        assert!(
            !testing_disabled(&app),
            "#717: a done work row with a branch must ENABLE the interactive Testing action"
        );
    }

    /// #717 black-box (TuiDriver): with a completed work row, opening the
    /// Pipeline row's context menu renders the interactive launcher menu through
    /// the real event → render path against the headless `TestBackend`.
    #[test]
    fn tuidriver_done_work_row_renders_interactive_menu() {
        use quadraui::tui::testing::driver_with_shell;

        let mut app = make_pipeline_app_with_test_gate();
        app.active_view = SidebarView::Pipeline;
        app.pipeline_sel = Some(0);
        let mut row = _work_assignment("w1", 100.0, "done", None);
        row.branch = Some("issue-42-add-cool-thing".to_string());
        app.data.assignments.push(row);

        // Open the row's context menu (the same state a right-click produces).
        let opened = app.open_context_menu(Point::new(4.0, 4.0), pipeline_target(Some(42)));
        assert!(opened, "context menu should open for the pipeline row");

        let driver = driver_with_shell(app, CoordApp::shell_config(), 120, 40);
        assert!(
            driver.screen_contains("Start (interactive)"),
            "the interactive launcher menu must render for a done work row:\n{}",
            driver.screen()
        );
    }

    // ── #1104: Continue — failed-with-branch work-attempt menu item ───────

    /// #1104 black-box (TuiDriver): a work row that FAILED outright (not a
    /// test/review gate) while leaving a real branch behind must still
    /// render the "Start (interactive)" launcher menu end-to-end through
    /// the real event → render path against the headless `TestBackend` —
    /// the same render-pipeline sanity check the `Fix`/`Testing` gates use
    /// (see `tuidriver_done_work_row_renders_interactive_menu` above). The
    /// exact gating logic (Continue shown/hidden) is covered by the
    /// builder-level `context_menu_shows_continue_only_when_latest_work_
    /// attempt_failed_with_branch` / `context_menu_hides_continue_when_no_
    /// failed_branched_attempt` tests.
    #[test]
    fn tuidriver_failed_work_row_with_branch_renders_interactive_menu() {
        use quadraui::tui::testing::driver_with_shell;

        let mut app = make_pipeline_app_with_test_gate();
        app.active_view = SidebarView::Pipeline;
        app.pipeline_sel = Some(0);

        // Worker-reported failure (no test/review gate) that left a real
        // branch behind — the shape #1104's Continue targets.
        let mut row = _work_assignment("w1", 100.0, "failed", None);
        row.branch = Some("issue-42-add-cool-thing".to_string());
        app.data.assignments.push(row);

        let opened = app.open_context_menu(Point::new(4.0, 4.0), pipeline_target(Some(42)));
        assert!(opened, "context menu should open for the pipeline row");

        let driver = driver_with_shell(app, CoordApp::shell_config(), 120, 40);
        assert!(
            driver.screen_contains("Start (interactive)"),
            "the interactive launcher menu must render for a failed-with-branch work row:\n{}",
            driver.screen()
        );
    }

    /// #727 black-box (TuiDriver): a work row with `status=done` AND a
    /// matching `live_tmux_sessions` entry (zombie — assignment finalised but
    /// tmux still alive) must render **both** "Reattach to live session" AND
    /// "Start (interactive)" in its right-click context menu.
    ///
    /// This drives the full `open_context_menu → render_frame` path against
    /// the headless `TestBackend`, confirming the menu gate change
    /// (`issue_has_any_discovered_session`) is reflected on screen.
    #[test]
    fn tuidriver_zombie_session_menu_shows_reattach_and_start() {
        use quadraui::tui::testing::driver_with_shell;

        let mut app = make_pipeline_app_with_test_gate();
        app.active_view = SidebarView::Pipeline;
        app.pipeline_sel = Some(0);

        // Zombie: work is done (finalised), but the tmux session is still alive.
        // `_work_assignment` / `_stage_assignment` already sets issue_number=42
        // and repo="api", which matches make_pipeline_app_with_test_gate's issue.
        let mut row = _work_assignment("w-zombie", 100.0, "done", None);
        row.branch = Some("issue-42-zombie".to_string());
        app.data.assignments.push(row);
        app.live_tmux_sessions = vec![LiveTmuxSession {
            assignment_id: "w-zombie".to_string(),
            issue_number: Some(42),
            repo_name: Some("api".to_string()),
            issue_title: None,
            machine: None,
            pane_dead: false,
            pending_sweep_count: 0,
            attached: false,
        }];

        // Open the context menu for the pipeline row (same state as right-click).
        let opened = app.open_context_menu(Point::new(4.0, 4.0), pipeline_target(Some(42)));
        assert!(opened, "context menu should open for the pipeline row");

        let driver = driver_with_shell(app, CoordApp::shell_config(), 120, 40);

        assert!(
            driver.screen_contains("Reattach to live session"),
            "#727: zombie row must render 'Reattach to live session' in the context menu:\n{}",
            driver.screen()
        );
        assert!(
            driver.screen_contains("Start (interactive)"),
            "#727: zombie right-click menu must also render 'Start (interactive)' \
             (not hard-locked to Reattach-only):\n{}",
            driver.screen()
        );
    }

    // ── #722: live-session gate — TuiDriver black-box screen test ───────────

    /// When `pending_auto_review` is set but a running remote tmux session
    /// exists for the same issue, the TUI must render the "Reattach to live
    /// session" dialog — NOT the normal "Start review" dialog.
    ///
    /// This exercises the full `build_prompt_dialog` → `render_prompt_dialog`
    /// path via the real `ShellAdapter` → `TestBackend` pipeline.
    #[test]
    fn tuidriver_live_session_blocks_auto_review_dialog() {
        use quadraui::tui::testing::driver_with_shell;

        // Running assignment that backs the live tmux session.
        let running_work = make_assignment_typed("running", 10, "repo-a", Some("work"));
        let running_aid = running_work.id.clone();

        let mut app = make_app_with_assignments(vec![running_work]);
        // Add the synthetic live tmux session (simulates a remote fleet machine).
        app.live_tmux_sessions.push(make_live_tmux_session(&running_aid, 10, "repo-a"));
        // Directly set the pending offer (simulates the detector having fired in
        // a race before the session appeared, or manual advance).
        app.pending_auto_review = Some(mk_pending_auto_review("repo-a", 10));

        let driver = driver_with_shell(app, CoordApp::shell_config(), 120, 40);
        let screen = driver.screen();

        // The live-session-blocking dialog body must mention reattaching.
        assert!(
            driver.screen_contains("Reattach to live session"),
            "screen must contain 'Reattach to live session' when a live session is \
             blocking the offer:\n{screen}",
        );
        // The normal "Start review" button must NOT be present.
        assert!(
            !driver.screen_contains("Start review"),
            "normal 'Start review' action must be suppressed while session is live:\n{screen}",
        );
    }

    // ── #669: issue_body_list word-wrap ──────────────────────────────────────

    /// A long plain-text body line must produce more ListView rows than the
    /// unwrapped (width=0) path when a narrow wrap width is given.
    #[test]
    fn issue_body_list_long_line_wraps() {
        // A single line of 120 chars — much wider than our wrap width of 40.
        let body = "a".repeat(120);
        let issue = Some((1u64, "Title", body.as_str(), [].as_slice()));

        let unwrapped = issue_body_list(issue, 0, "test-unwrapped", 0);
        let wrapped = issue_body_list(issue, 0, "test-wrapped", 40);

        // header + blank separator + body lines.
        // The wrapped list must have more rows than the unwrapped one.
        assert!(
            wrapped.items.len() > unwrapped.items.len(),
            "wrapped list ({} items) should have more rows than unwrapped ({} items) \
             for a 120-char line at width 40",
            wrapped.items.len(),
            unwrapped.items.len(),
        );
    }

    /// A fenced code block must not be split across rows by wrapping.
    /// Both unwrapped and wrapped outputs must produce the same row count for
    /// content that is entirely inside a fenced code block.
    #[test]
    fn issue_body_list_code_block_not_wrapped() {
        // One long line inside a fenced code block.
        let long_code = "x".repeat(200);
        let body = format!("```\n{}\n```", long_code);
        let issue = Some((2u64, "Code", body.as_str(), [].as_slice()));

        let unwrapped = issue_body_list(issue, 0, "test-code-unwrapped", 0);
        let wrapped = issue_body_list(issue, 0, "test-code-wrapped", 40);

        // The code block interior must not be word-wrapped, so both paths
        // produce the same number of rows.
        assert_eq!(
            unwrapped.items.len(),
            wrapped.items.len(),
            "fenced code block must not be wrapped (unwrapped={} rows, wrapped={} rows)",
            unwrapped.items.len(),
            wrapped.items.len(),
        );
    }

    /// width == 0 must fall back to the unwrapped path: two calls with the
    /// same body and width=0 must produce the same row count.
    #[test]
    fn issue_body_list_zero_width_falls_back() {
        let body = "Short line.";
        let issue = Some((3u64, "Short", body, [].as_slice()));

        let a = issue_body_list(issue, 0, "test-a", 0);
        let b = issue_body_list(issue, 0, "test-b", 0);

        assert_eq!(
            a.items.len(),
            b.items.len(),
            "width=0 must be deterministic and unwrapped"
        );
    }

