    /// #1001: pressing `u` on a tracked row expands that row's repo,
    /// revealing the previously-collapsed `no_work_order` milestone
    /// ("Follow-up") inline with its `no_work_order` chip; pressing `u`
    /// again re-collapses it.
    #[test]
    fn plans_panel_u_toggles_untracked_milestones_for_selected_repo() {
        use quadraui::tui::testing::driver_with_shell;

        let app = make_test_app(make_plan_roster_board_data());
        let mut driver = driver_with_shell(app, CoordApp::shell_config(), 140, 40);
        click_activity_icon(&mut driver, "◆");

        assert!(
            !driver.screen_contains("Follow-up"),
            "sanity: Follow-up starts collapsed:\n{}",
            driver.screen(),
        );

        driver.press(quadraui::Key::Char('u'));
        let screen = driver.screen();
        assert!(
            screen.contains("Follow-up"),
            "#1001: `u` must expand the selected row's repo, revealing Follow-up:\n{screen}",
        );
        assert!(
            screen.contains("no_work_order"),
            "#1001: the revealed row must still carry its `no_work_order` chip:\n{screen}",
        );
        assert!(
            !screen.contains("without a work order"),
            "#1001: the '+N without a work order' summary must disappear once expanded:\n{screen}",
        );

        // Toggle again — back to collapsed.
        driver.press(quadraui::Key::Char('u'));
        let screen = driver.screen();
        assert!(
            !screen.contains("Follow-up"),
            "#1001: a second `u` must re-collapse the repo:\n{screen}",
        );
        assert!(
            screen.contains("+1 without a work order"),
            "#1001: re-collapsing must restore the summary line:\n{screen}",
        );
    }

    /// #1003 fix-up: a real right-click (full `UiEvent::MouseDown { button:
    /// Right }` → `handle` → `open_context_menu` path, same as
    /// `tuidriver_right_click_opens_board_context_menu`) on a Plans-panel row
    /// must open the CRUD context menu. Before this fix, `handle_mouse`'s
    /// right-click arm only ever tried `ctx.in_sidebar(..)` — the Plans
    /// roster lives in the *main* panel, so every right-click there fell
    /// through as a silent no-op and the menu this issue promises was
    /// unreachable by mouse (the only coverage that existed called
    /// `context_menu_target_for_selection()` directly, bypassing the mouse
    /// hit-test entirely and masking the gap).
    #[test]
    fn tuidriver_right_click_on_plans_row_opens_context_menu() {
        use quadraui::tui::testing::driver_with_shell;

        let app = make_test_app(make_plan_roster_board_data());
        let mut driver = driver_with_shell(app, CoordApp::shell_config(), 140, 40);
        click_activity_icon(&mut driver, "◆");

        let (x, y) = driver.find("Substrate").unwrap_or_else(|| {
            panic!(
                "#1003: could not find Plans row 'Substrate' on initial render:\n{}",
                driver.screen()
            )
        });

        driver.dispatch(UiEvent::MouseDown {
            widget: None,
            button: MouseButton::Right,
            position: Point::new(x, y),
            modifiers: Modifiers::default(),
        });

        let screen = driver.screen();
        assert!(
            screen.contains("Open milestone chat"),
            "#1003: right-click on a Plans row must open the CRUD context menu:\n{}",
            screen
        );
    }

    /// #1029 fix-iteration regression (bug A): opening milestone chat from
    /// the Plans panel must update quadraui's ActivityBar highlight AND
    /// sidebar panel header, not just the main-pane content. Before this
    /// fix, `launch_milestone_chat_session` set `active_view` via a raw
    /// field write, which `render_content`'s `match self.active_view` obeys
    /// (so the sidebar tree + main pane *did* switch to Terminal) but which
    /// `AppShell` never learns about — its own `active_panel` index (which
    /// drives the ActivityBar highlight and the "PLANS"/"TERMINAL" sidebar
    /// header text) is private state only mutated by a mouse click or the
    /// `ShellApp::take_requested_panel` hook. Drives the exact reviewer
    /// repro end-to-end: right-click a Plans row, click "Open milestone
    /// chat", assert the header follows.
    #[test]
    #[cfg(unix)]
    fn tuidriver_open_milestone_chat_updates_activity_chrome_not_just_content() {
        use quadraui::tui::testing::driver_with_shell;

        let mut app = make_test_app(make_plan_roster_board_data());
        app.command_runner = crate::commands::CommandRunner::new_for_test();
        let mut driver = driver_with_shell(app, CoordApp::shell_config(), 140, 40);
        click_activity_icon(&mut driver, "◆");

        assert!(
            driver.screen_contains("PLANS"),
            "sanity: sidebar header should read PLANS before opening chat:\n{}",
            driver.screen()
        );

        let (x, y) = driver.find("Substrate").unwrap_or_else(|| {
            panic!(
                "could not find Plans row 'Substrate' on initial render:\n{}",
                driver.screen()
            )
        });
        driver.dispatch(UiEvent::MouseDown {
            widget: None,
            button: MouseButton::Right,
            position: Point::new(x, y),
            modifiers: Modifiers::default(),
        });
        assert!(
            driver.screen_contains("Open milestone chat"),
            "context menu should be open with 'Open milestone chat' as its \
             first (pre-selected) item:\n{}",
            driver.screen()
        );
        // Activate the pre-selected first item ("Open milestone chat") via
        // Enter rather than a second mouse click — a mouse click on this
        // particular menu's item rows is a separate, pre-existing quadraui
        // hit-test/paint offset (menu item hit-regions don't account for
        // the border row the TUI rasteriser draws around them) unrelated to
        // #1029; Enter drives `context_menu_activate_selected`, which acts
        // on `selected_idx` directly and isn't affected by that offset.
        driver.press_named(NamedKey::Enter);

        let screen = driver.screen();
        assert!(
            screen.contains("TERMINAL"),
            "sidebar header must follow the programmatic switch to the \
             Terminal view, matching the sidebar tree + main pane that \
             already switched:\n{}",
            screen
        );
        assert!(
            !screen.contains("PLANS"),
            "the stale PLANS header must not still be showing once \
             milestone chat is open (#1029 bug A):\n{}",
            screen
        );
    }

    /// #1029 fix-iteration regression (bug B): once PTY focus is released
    /// (F12), Esc must return the operator to the Plans panel milestone
    /// chat was opened from — the issue's explicit "Esc/detach returns
    /// focus to the originating Plans/milestone view" promise. Before this
    /// fix there was no origin-tracking state at all, so Esc did nothing
    /// and the operator had to navigate back to Plans manually.
    #[test]
    #[cfg(unix)]
    fn tuidriver_esc_after_releasing_pty_focus_returns_to_plans_origin() {
        use quadraui::tui::testing::driver_with_shell;

        let mut app = make_test_app(make_plan_roster_board_data());
        app.command_runner = crate::commands::CommandRunner::new_for_test();
        let mut driver = driver_with_shell(app, CoordApp::shell_config(), 140, 40);
        click_activity_icon(&mut driver, "◆");

        let (x, y) = driver.find("Substrate").unwrap_or_else(|| {
            panic!(
                "could not find Plans row 'Substrate' on initial render:\n{}",
                driver.screen()
            )
        });
        driver.dispatch(UiEvent::MouseDown {
            widget: None,
            button: MouseButton::Right,
            position: Point::new(x, y),
            modifiers: Modifiers::default(),
        });
        // Activate the pre-selected first item ("Open milestone chat") via
        // Enter — see the sibling chrome-desync test for why not a second
        // mouse click on the menu itself.
        driver.press_named(NamedKey::Enter);
        assert!(
            driver.screen_contains("TERMINAL"),
            "sanity: should have landed on Terminal after opening chat:\n{}",
            driver.screen()
        );

        // Entering Terminal auto-focuses the PTY (#424) — Esc must not leak
        // into the shell while focused, so release focus first (F12), the
        // same way the operator would per the status-bar hint.
        driver.press_named(NamedKey::F(12));
        driver.press_named(NamedKey::Escape);

        let screen = driver.screen();
        assert!(
            screen.contains("PLANS"),
            "Esc (once PTY focus is released) must return to the \
             originating Plans view (#1029 bug B):\n{}",
            screen
        );
        assert!(
            !screen.contains("TERMINAL"),
            "must have actually left the Terminal view, not just repainted \
             its own chrome:\n{}",
            screen
        );
    }

    /// #1029 bug B (iter-2 review finding): `switch_active_view` must clear a
    /// pre-existing `terminal_return_view` bookmark on EVERY switch — crucially
    /// including a switch *into* Terminal for an unrelated reason
    /// (review/fix/merge/fleet-terminal/reattach). The iter-1 fix only cleared
    /// when the target wasn't Terminal, so a milestone-chat bookmark leaked
    /// across a later, unrelated Terminal visit and Esc teleported the operator
    /// out of a live review session to the stale Plans origin.
    #[test]
    fn switch_active_view_into_terminal_clears_stale_return_bookmark() {
        let mut app = make_app_default();
        // Simulate the leftover state after a milestone chat was opened and
        // the operator navigated away: a bookmark still parked on Plans.
        app.terminal_return_view = Some(SidebarView::Plans);

        // An unrelated flow (Start review/fix/merge, fleet-terminal, reattach
        // from the live-sessions overlay) lands on Terminal via
        // `switch_active_view` — it must NOT inherit the stale bookmark.
        app.switch_active_view(SidebarView::Terminal);

        assert_eq!(
            app.terminal_return_view, None,
            "an unrelated switch into Terminal must clear the stale \
             milestone-chat bookmark so Esc has nothing to replay"
        );
    }

    /// Companion to the above: `launch_milestone_chat_session` re-sets its
    /// bookmark *after* the (now-clearing) switch, so the legitimate return
    /// path still works — the bookmark points at the pre-launch origin.
    #[test]
    #[cfg(unix)]
    fn launch_milestone_chat_session_bookmarks_origin_after_clearing_switch() {
        let mut app = make_test_app(make_plan_roster_board_data());
        app.command_runner = crate::commands::CommandRunner::new_for_test();
        app.active_view = SidebarView::Plans;

        app.launch_milestone_chat_session("api".to_string(), 500, None);

        assert_eq!(
            app.active_view,
            SidebarView::Terminal,
            "milestone chat lands on the Terminal view"
        );
        assert_eq!(
            app.terminal_return_view,
            Some(SidebarView::Plans),
            "the origin (Plans) must survive the clearing switch, re-set \
             afterwards, so Esc returns there (#1029 bug B)"
        );
    }

    /// #1029 bug B (iter-2 review finding) — full mouse-driven repro through
    /// the real shell event path: a stale milestone-chat bookmark must not
    /// survive ordinary ActivityBar navigation and teleport the operator out
    /// of a later, unrelated Terminal visit. A *real* ActivityBar click is a
    /// fresh operator choice and invalidates the bookmark; only the
    /// programmatic replay of our own queued switch is exempt.
    #[test]
    #[cfg(unix)]
    fn tuidriver_stale_bookmark_cleared_by_activitybar_navigation() {
        use quadraui::tui::testing::driver_with_shell;

        let mut app = make_test_app(make_plan_roster_board_data());
        app.command_runner = crate::commands::CommandRunner::new_for_test();
        let mut driver = driver_with_shell(app, CoordApp::shell_config(), 140, 40);
        click_activity_icon(&mut driver, "◆");

        // 1. Open milestone chat from Plans → bookmark = Some(Plans), Terminal.
        let (x, y) = driver.find("Substrate").unwrap_or_else(|| {
            panic!(
                "could not find Plans row 'Substrate' on initial render:\n{}",
                driver.screen()
            )
        });
        driver.dispatch(UiEvent::MouseDown {
            widget: None,
            button: MouseButton::Right,
            position: Point::new(x, y),
            modifiers: Modifiers::default(),
        });
        driver.press_named(NamedKey::Enter);
        assert!(
            driver.screen_contains("TERMINAL"),
            "sanity: should have landed on Terminal after opening chat:\n{}",
            driver.screen()
        );

        // 2. Ordinary ActivityBar navigation away (Board). A real click is a
        //    fresh operator choice → the stale bookmark is invalidated. The
        //    "B" glyph the activity bar paints for Board sits at the very top
        //    of the screen (row 0, col 1), so `find("B")` lands on it.
        click_activity_icon(&mut driver, "B");
        assert!(
            driver.screen_contains("BOARD"),
            "sanity: clicking the Board icon should switch to Board:\n{}",
            driver.screen()
        );

        // 3. A later, unrelated fresh visit back to the Terminal panel (plain
        //    ActivityBar click) has nothing to return to. The activity bar
        //    paints only the first char of each icon (quadraui
        //    `activity_bar.rs`), so the ">_" Terminal glyph shows as ">".
        //    (We navigate away via Board rather than Pipeline because a
        //    pre-existing quadraui quirk swallows activity-bar clicks on the
        //    rows immediately adjacent to a selected Pipeline row — unrelated
        //    to #1029; clicking the Terminal icon from Board is unaffected.)
        click_activity_icon(&mut driver, ">");
        assert!(
            driver.screen_contains("TERMINAL"),
            "sanity: clicking the Terminal icon should switch to Terminal:\n{}",
            driver.screen()
        );

        // 4. Release PTY focus and press Esc — with the stale bookmark cleared
        //    by the navigation in step 2, Esc must NOT teleport to Plans; the
        //    operator stays on this plain Terminal visit. Before the iter-2
        //    fix the bookmark leaked and Esc jumped them to the stale PLANS.
        driver.press_named(NamedKey::F(12));
        driver.press_named(NamedKey::Escape);
        let screen = driver.screen();
        assert!(
            screen.contains("TERMINAL"),
            "Esc on a plain Terminal visit (no bookmark) must not teleport \
             the operator to the stale Plans origin:\n{}",
            screen
        );
        assert!(
            !screen.contains("PLANS"),
            "the stale PLANS bookmark must not have replayed a jump:\n{}",
            screen
        );
    }

    /// #1003/#1001 rebase regression: once the roster spans more than one
    /// repo group, `render_plans_panel` (#1001) interleaves a non-selectable
    /// header row per repo and an optional trailing "+N without a work
    /// order" summary row, and `plans_sel` indexes into
    /// `plans_visible_entries()` — NOT the flat, header-blind
    /// `plans_entries()` shape `plans_row_at` was originally written
    /// against (pre-#1001). Left-clicking a row belonging to the *second*
    /// repo group must select that exact row (verified by pressing Enter
    /// afterwards and checking which tracking epic opens) — not some other
    /// row shifted by the intervening header/summary rows.
    #[test]
    fn plans_panel_click_on_second_repo_row_selects_correct_row() {
        use quadraui::tui::testing::driver_with_shell;

        let board = BoardData {
            pipeline_default_gates: vec!["review".to_string(), "merge".to_string()],
            pipeline_tracked_labels: vec!["coord".to_string()],
            pipeline_repos: vec![
                ("api".to_string(), "acme/api".to_string()),
                ("web".to_string(), "acme/web".to_string()),
            ],
            plan_roster_supported: true,
            plan_roster: vec![
                PlanRosterEntry {
                    repo: "api".to_string(),
                    title: "Substrate".to_string(),
                    milestone_number: 5,
                    tracking_issue: Some(500),
                    has_work_order: true,
                    ready_frontier: 2,
                    blocked: 1,
                    total: 3,
                    needs_you: vec!["ready_waiting".to_string()],
                    ..Default::default()
                },
                // Untracked + not expanded → collapsed into the "+1 without
                // a work order" summary line (its own non-selectable row),
                // not its own selectable row — exercises the summary-row
                // offset, not just the header-row offset.
                PlanRosterEntry {
                    repo: "api".to_string(),
                    title: "Follow-up".to_string(),
                    milestone_number: 6,
                    ..Default::default()
                },
                PlanRosterEntry {
                    repo: "web".to_string(),
                    title: "Frontend Revamp".to_string(),
                    milestone_number: 12,
                    tracking_issue: Some(1200),
                    has_work_order: true,
                    ready_frontier: 1,
                    total: 1,
                    ..Default::default()
                },
            ],
            ..BoardData::default()
        };

        let app = make_test_app(board);
        let mut driver = driver_with_shell(app, CoordApp::shell_config(), 140, 40);
        click_activity_icon(&mut driver, "◆");

        let (x, y) = driver.find("Frontend Revamp").unwrap_or_else(|| {
            panic!(
                "could not find Plans row 'Frontend Revamp' on initial render:\n{}",
                driver.screen()
            )
        });
        driver.click(x, y);
        driver.press_named(quadraui::NamedKey::Enter);

        let screen = driver.screen();
        assert!(
            screen.contains("Opening plan"),
            "clicking a Plans row then pressing Enter must fire the 'Opening \
             plan' toast:\n{}",
            screen,
        );
        // Both #500 (Substrate) and #1200 (Frontend Revamp) are always
        // visible as static row text regardless of selection, so scope the
        // assertion to the toast line itself rather than the whole screen.
        let toast_line = screen
            .lines()
            .find(|line| line.contains("gh issue view"))
            .unwrap_or_else(|| panic!("no 'gh issue view' toast line found:\n{screen}"));
        assert!(
            toast_line.contains("#1200"),
            "clicking the second repo's row then pressing Enter must open ITS \
             tracking epic (#1200), not the first repo's (#500) — a \
             header/summary-row count mismatch in `plans_row_at` mis-maps \
             the click to the wrong row:\n{}",
            screen,
        );
    }

    /// After landing on Plans, pressing Enter on the selected row opens the
    /// tracking epic (visible as an "Opening plan" toast in-test — the real
    /// `gh` spawn is `#[cfg(not(test))]`-gated to keep the sandbox hermetic).
    /// Pressing j once first moves selection to the second row (Follow-up),
    /// which has no epic — that path must surface a "No tracking epic yet"
    /// toast rather than opening a bogus URL.
