    // ── #953: Terminal-view left-pane machine tree ──────────────────────────

    /// TuiDriver black-box: seed 2 machines — one with 2 discovered
    /// `FleetTerminal`s, one with none — open the Terminal view and assert
    /// the left-pane tree renders machines as parents with their terminals
    /// nested directly beneath the correct machine (not interleaved with
    /// the other machine's rows), and that the empty machine renders with
    /// no terminal children at all.
    #[test]
    fn terminal_tree_groups_terminals_under_correct_machine() {
        use quadraui::tui::testing::driver_with_shell;

        let mut app = make_test_app(BoardData {
            machines: vec![
                mk_machine("precision", "precision.tail", true, &[]),
                mk_machine("dellserver", "dellserver.tail", true, &[]),
            ],
            ..BoardData::default()
        });
        app.fleet_terminals = vec![
            FleetTerminal {
                name: "scratch".to_string(),
                machine: "precision".to_string(),
                attached: false,
                pending: false,
                pending_sweep_count: 0,
            },
            FleetTerminal {
                name: "build".to_string(),
                machine: "precision".to_string(),
                attached: true,
                pending: false,
                pending_sweep_count: 0,
            },
        ];

        let mut driver = driver_with_shell(app, CoordApp::shell_config(), 120, 40);
        click_activity_icon(&mut driver, ">");

        let screen = driver.screen();
        assert!(
            screen.contains("precision"),
            "machine 'precision' should render as a tree parent:\n{screen}",
        );
        assert!(
            screen.contains("dellserver"),
            "machine 'dellserver' should render as a tree parent even with no terminals:\n{screen}",
        );
        assert!(
            screen.contains("scratch"),
            "'precision' terminal 'scratch' should be nested in the tree:\n{screen}",
        );
        assert!(
            screen.contains("build"),
            "'precision' terminal 'build' should be nested in the tree:\n{screen}",
        );

        // Nesting: both terminal rows must appear strictly between the
        // "precision" row and the "dellserver" row — i.e. under the correct
        // machine, not after the empty machine's (childless) row.
        let lines: Vec<&str> = screen.lines().collect();
        let precision_row = lines
            .iter()
            .position(|l| l.contains("precision"))
            .expect("precision row");
        let dellserver_row = lines
            .iter()
            .position(|l| l.contains("dellserver"))
            .expect("dellserver row");
        let scratch_row = lines
            .iter()
            .position(|l| l.contains("scratch"))
            .expect("scratch row");
        let build_row = lines
            .iter()
            .position(|l| l.contains("build"))
            .expect("build row");
        assert!(
            precision_row < scratch_row
                && scratch_row < dellserver_row
                && precision_row < build_row
                && build_row < dellserver_row,
            "terminals must be nested between their machine's row and the next \
             machine's row (precision={precision_row}, scratch={scratch_row}, \
             build={build_row}, dellserver={dellserver_row}):\n{screen}",
        );

        // The empty machine ('dellserver') must render with no children: no
        // terminal name appears on or after its own row.
        assert!(
            !lines[dellserver_row..]
                .iter()
                .any(|l| l.contains("scratch") || l.contains("build")),
            "'dellserver' has no terminals and must render with no nested children:\n{screen}",
        );
    }

    // ── #1032: Sessions-view left-pane machine → repo → session tree ────────

    /// TuiDriver black-box: seed live sessions across 2 machines and 2
    /// repos — one attached, one plain detached, one dead-pane — open the
    /// Sessions view and assert the left-pane tree nests machine → repo →
    /// session correctly and tags `[attached]` / `(dead)` sessions.
    #[test]
    fn sessions_tree_nests_machine_repo_session_and_shows_status_tags() {
        use quadraui::tui::testing::driver_with_shell;

        let mut app = make_test_app(BoardData {
            machines: vec![
                mk_machine("precision", "precision.tail", true, &[]),
                mk_machine("dellserver", "dellserver.tail", true, &[]),
            ],
            ..BoardData::default()
        });
        app.live_tmux_sessions = vec![
            // precision / repo-a: one attached session.
            LiveTmuxSession {
                assignment_id: "aid-attached".to_string(),
                issue_number: Some(101),
                repo_name: Some("repo-a".to_string()),
                issue_title: None,
                machine: Some("precision".to_string()),
                pane_dead: false,
                pending_sweep_count: 0,
                attached: true,
            },
            // precision / repo-b: one plain detached session.
            LiveTmuxSession {
                assignment_id: "aid-detached".to_string(),
                issue_number: Some(202),
                repo_name: Some("repo-b".to_string()),
                issue_title: None,
                machine: Some("precision".to_string()),
                pane_dead: false,
                pending_sweep_count: 0,
                attached: false,
            },
            // dellserver / repo-a: one dead-pane session.
            LiveTmuxSession {
                assignment_id: "aid-dead".to_string(),
                issue_number: Some(303),
                repo_name: Some("repo-a".to_string()),
                issue_title: None,
                machine: Some("dellserver".to_string()),
                pane_dead: true,
                pending_sweep_count: 0,
                attached: false,
            },
        ];

        let mut driver = driver_with_shell(app, CoordApp::shell_config(), 120, 40);
        click_activity_icon(&mut driver, "◉");

        let screen = driver.screen();
        assert!(
            screen.contains("precision"),
            "machine 'precision' should render as a tree parent:\n{screen}",
        );
        assert!(
            screen.contains("dellserver"),
            "machine 'dellserver' should render as a tree parent:\n{screen}",
        );
        assert!(
            screen.contains("repo-a"),
            "'repo-a' group should be nested under both machines:\n{screen}",
        );
        assert!(
            screen.contains("repo-b"),
            "'repo-b' group should be nested under 'precision':\n{screen}",
        );
        assert!(
            screen.contains("#101") && screen.contains("[attached]"),
            "the attached session should show its issue # and an [attached] tag:\n{screen}",
        );
        assert!(
            screen.contains("#202"),
            "the plain detached session should render with no status tag:\n{screen}",
        );
        assert!(
            screen.contains("#303") && screen.contains("(dead)"),
            "the dead-pane session should show its issue # and a (dead) tag:\n{screen}",
        );

        // Nesting: machine → repo → session — every row for a machine's
        // sessions must appear strictly between that machine's row and the
        // next machine's row.
        let lines: Vec<&str> = screen.lines().collect();
        let precision_row = lines
            .iter()
            .position(|l| l.contains("precision"))
            .expect("precision row");
        let dellserver_row = lines
            .iter()
            .position(|l| l.contains("dellserver"))
            .expect("dellserver row");
        let repo_a_rows: Vec<usize> = lines
            .iter()
            .enumerate()
            .filter(|(_, l)| l.contains("repo-a"))
            .map(|(i, _)| i)
            .collect();
        let repo_b_row = lines
            .iter()
            .position(|l| l.contains("repo-b"))
            .expect("repo-b row");
        let attached_row = lines
            .iter()
            .position(|l| l.contains("#101"))
            .expect("#101 row");
        let detached_row = lines
            .iter()
            .position(|l| l.contains("#202"))
            .expect("#202 row");
        let dead_row = lines
            .iter()
            .position(|l| l.contains("#303"))
            .expect("#303 row");

        assert_eq!(
            repo_a_rows.len(),
            2,
            "'repo-a' should appear once per machine that hosts it:\n{screen}"
        );
        let precision_repo_a_row = repo_a_rows[0];
        let dellserver_repo_a_row = repo_a_rows[1];
        assert!(
            precision_row < precision_repo_a_row
                && precision_repo_a_row < attached_row
                && attached_row < repo_b_row
                && repo_b_row < detached_row
                && detached_row < dellserver_row,
            "precision's repo-a/repo-b groups and sessions must nest between \
             precision's row and dellserver's row (precision={precision_row}, \
             repo-a={precision_repo_a_row}, #101={attached_row}, repo-b={repo_b_row}, \
             #202={detached_row}, dellserver={dellserver_row}):\n{screen}",
        );
        assert!(
            dellserver_row < dellserver_repo_a_row && dellserver_repo_a_row < dead_row,
            "dellserver's repo-a group and session must nest after dellserver's row \
             (dellserver={dellserver_row}, repo-a={dellserver_repo_a_row}, #303={dead_row}):\n{screen}",
        );
    }

    // ── #955: attach & switch the selected terminal in the main pane ────────

    /// #955 TuiDriver black-box: with 2 fleet terminals discovered, clicking
    /// each tree leaf in turn must switch the standalone Terminal view's
    /// main pane to THAT leaf's attach target.
    ///
    /// The actual `coord terminal attach <machine:name>` PTY is spawned
    /// lazily by `tick()` (`drive_terminal_pane`) — but only the live
    /// runner's loop calls `AppLogic::tick` (`quadraui::tui::run::run_inner`);
    /// `TuiDriver::dispatch` (which every click/key goes through) does not.
    /// So this test asserts on the pre-attach placeholder
    /// (`"Attaching to <machine:name>…"`, `render.rs`'s `SidebarView::Terminal`
    /// branch), which already reflects the selected leaf's target — proving
    /// the click→selection→main-pane wiring without needing a live PTY. The
    /// PTY itself (real attach command reaching a real shell) is covered by
    /// `selecting_fleet_terminal_attaches_and_keeps_prior_session_warm`
    /// below, which drives `drive_terminal_pane` directly. Raw
    /// terminal-protocol fidelity is out of `TestBackend`'s reach per this
    /// repo's CLAUDE.md — a live smoke covers that.
    #[test]
    fn selecting_tree_leaf_switches_main_pane_attach_target() {
        use quadraui::tui::testing::driver_with_shell;

        let mut app = make_test_app(BoardData {
            machines: vec![mk_machine("precision", "precision.tail", true, &[])],
            ..BoardData::default()
        });
        app.fleet_terminals = vec![
            FleetTerminal {
                name: "scratch".to_string(),
                machine: "precision".to_string(),
                attached: false,
                pending: false,
                pending_sweep_count: 0,
            },
            FleetTerminal {
                name: "build".to_string(),
                machine: "precision".to_string(),
                attached: false,
                pending: false,
                pending_sweep_count: 0,
            },
        ];

        let mut driver = driver_with_shell(app, CoordApp::shell_config(), 120, 40);
        // The activity bar column truncates the ">_" Terminal icon down to
        // just ">" at this width (mirrors the #953 tree test's icon lookup).
        click_activity_icon(&mut driver, ">");

        // Select "scratch".
        let (x, y) = driver.find("scratch").unwrap_or_else(|| {
            panic!("'scratch' row not found:\n{}", driver.screen())
        });
        driver.click(x, y);
        let screen = driver.screen();
        assert!(
            screen.contains("Attaching to precision:scratch"),
            "selecting 'scratch' should target precision:scratch in the main pane:\n{screen}",
        );
        assert!(
            !screen.contains("Attaching to precision:build"),
            "the 'build' leaf must not be the active attach target yet:\n{screen}",
        );

        // Select "build" — the main pane must switch to it. The two rows
        // sit one cell apart, so back-to-back clicks land inside
        // quadraui's double-click detector's radius/time window (400ms /
        // 1.5 cells — `tui/events.rs::DoubleClickDetector`) and would
        // otherwise fold into a `DoubleClick` event the tree doesn't
        // handle, silently dropping the second click. Sleeping past the
        // window keeps this a plain two-click sequence.
        std::thread::sleep(std::time::Duration::from_millis(450));
        let (x, y) = driver.find("build").unwrap_or_else(|| {
            panic!("'build' row not found:\n{}", driver.screen())
        });
        driver.click(x, y);
        let screen = driver.screen();
        assert!(
            screen.contains("Attaching to precision:build"),
            "selecting 'build' should switch the main pane to precision:build:\n{screen}",
        );
        assert!(
            !screen.contains("Attaching to precision:scratch"),
            "the previously-selected 'scratch' target must no longer be shown:\n{screen}",
        );
    }

    /// #955: selecting a fleet-terminal leaf attaches it — a local PTY
    /// running `coord terminal attach <machine:name>` — into
    /// `fleet_terminal_sessions`, and switching to a DIFFERENT leaf keeps
    /// the first session warm (cached, not evicted) while attaching the
    /// second; `standalone_pty_session()` always resolves to whichever leaf
    /// is currently selected. Drives a real spawned shell directly (mirrors
    /// the #464 host-selection tests' pattern) since `TuiDriver` cannot
    /// exercise `tick()` — see the black-box test above for the
    /// selection-only, no-tick surface.
    #[test]
    #[cfg(unix)]
    fn selecting_fleet_terminal_attaches_and_keeps_prior_session_warm() {
        use std::time::{Duration, Instant};

        fn poll_until(
            app: &mut CoordApp,
            key: &(String, String),
            max_ms: u64,
            predicate: impl Fn(&quadraui::terminal_engine::TerminalSession) -> bool,
        ) -> bool {
            let start = Instant::now();
            let limit = Duration::from_millis(max_ms);
            loop {
                app.drive_terminal_pane();
                if let Some(sess) = app.fleet_terminal_sessions.get(key) {
                    if predicate(sess) {
                        return true;
                    }
                }
                if start.elapsed() >= limit {
                    return false;
                }
                std::thread::sleep(Duration::from_millis(10));
            }
        }

        let mut app = make_test_app(BoardData {
            machines: vec![mk_machine("precision", "precision.tail", true, &[])],
            ..BoardData::default()
        });
        app.active_view = SidebarView::Terminal;
        app.fleet_terminals = vec![
            FleetTerminal {
                name: "scratch".to_string(),
                machine: "precision".to_string(),
                attached: false,
                pending: false,
                pending_sweep_count: 0,
            },
            FleetTerminal {
                name: "build".to_string(),
                machine: "precision".to_string(),
                attached: false,
                pending: false,
                pending_sweep_count: 0,
            },
        ];
        // `render_content` normally stashes this on the first paint;
        // simulate that a frame already happened so `drive_terminal_pane`
        // doesn't stall waiting for dims.
        app.terminal_pending_dims.set(Some((80, 24)));

        // Sorted-by-name per-machine list is ["build", "scratch"], so
        // "scratch" is tree index 1.
        app.terminal_tree_selected = Some(vec![0, 1]);
        let scratch_key = ("precision".to_string(), "scratch".to_string());
        assert!(
            poll_until(&mut app, &scratch_key, 5_000, |s| s
                .full_text()
                .contains("coord terminal attach")),
            "expected the attach command to appear in the 'scratch' PTY's output"
        );
        let scratch_text = app
            .fleet_terminal_sessions
            .get(&scratch_key)
            .unwrap()
            .full_text();
        assert!(
            scratch_text.contains("coord terminal attach 'precision:scratch'"),
            "attach command should target precision:scratch:\n{scratch_text}"
        );
        assert!(
            app.standalone_pty_session()
                .map(|s| s.full_text().contains("coord terminal attach"))
                .unwrap_or(false),
            "standalone_pty_session should resolve to the attached 'scratch' PTY"
        );

        // Switch selection to "build" (tree index 0).
        app.terminal_tree_selected = Some(vec![0, 0]);
        let build_key = ("precision".to_string(), "build".to_string());
        assert!(
            poll_until(&mut app, &build_key, 5_000, |s| s
                .full_text()
                .contains("coord terminal attach")),
            "expected the attach command to appear in the 'build' PTY's output"
        );
        let build_text = app
            .fleet_terminal_sessions
            .get(&build_key)
            .unwrap()
            .full_text();
        assert!(
            build_text.contains("coord terminal attach 'precision:build'"),
            "attach command should target precision:build:\n{build_text}"
        );

        // 'scratch' must still be cached (kept warm), not evicted by the switch.
        assert!(
            app.fleet_terminal_sessions.contains_key(&scratch_key),
            "switching away from 'scratch' must not evict its cached session"
        );

        // `standalone_pty_session` must now resolve to 'build'.
        let now_visible = app.standalone_pty_session().unwrap().full_text();
        assert!(
            now_visible.contains("coord terminal attach 'precision:build'"),
            "standalone_pty_session should switch to 'build' after re-selection:\n{now_visible}"
        );
    }

    /// #955 fix regression: dropping a cached fleet-terminal session (e.g.
    /// the whole TUI quitting) must DETACH the remote tmux client, never
    /// kill the session — that's the entire persistence guarantee `coord
    /// terminal new`/tmux is supposed to provide. Attaches to a REAL tmux
    /// session on a reachable fleet machine (`elitebook` in this repo's
    /// dev fleet), drops the cached `FleetTerminalSession` the same way
    /// `CoordApp` drops its `fleet_terminal_sessions` map on exit, and
    /// asserts the remote session is still listed afterward.
    ///
    /// `#[ignore]`d — needs a real `elitebook` host reachable over ssh
    /// with `coord`/`tmux` installed; not something CI can provide. Run
    /// manually with `cargo test --lib -- --ignored
    /// scratch_repro_quit_kills_remote_tmux_session`.
    #[test]
    #[ignore]
    #[cfg(unix)]
    fn dropping_fleet_terminal_session_detaches_not_kills_remote_tmux() {
        use std::time::{Duration, Instant};

        let sess_name = "coord-term-regress955";
        let _ = std::process::Command::new("ssh")
            .args(["elitebook", "tmux", "kill-session", "-t", sess_name])
            .status();
        let created = std::process::Command::new("ssh")
            .args(["elitebook", "tmux", "new-session", "-d", "-s", sess_name])
            .status()
            .expect("ssh new-session");
        assert!(created.success(), "failed to create remote session");

        let mut app = make_test_app(BoardData {
            machines: vec![mk_machine("elitebook", "elitebook", true, &[])],
            ..BoardData::default()
        });
        app.active_view = SidebarView::Terminal;
        app.fleet_terminals = vec![FleetTerminal {
            name: "regress955".to_string(),
            machine: "elitebook".to_string(),
            attached: false,
            pending: false,
            pending_sweep_count: 0,
        }];
        app.terminal_pending_dims.set(Some((80, 24)));
        app.terminal_tree_selected = Some(vec![0, 0]);

        let key = ("elitebook".to_string(), "regress955".to_string());
        let start = Instant::now();
        loop {
            app.drive_terminal_pane();
            if let Some(sess) = app.fleet_terminal_sessions.get(&key) {
                if sess.full_text().contains("coord terminal attach") {
                    break;
                }
            }
            assert!(start.elapsed() < Duration::from_secs(10), "attach never started");
            std::thread::sleep(Duration::from_millis(20));
        }
        // Let the ssh connection + tmux attach fully settle before tearing
        // down — attaching and immediately dropping wouldn't exercise the
        // race this test guards against.
        let settle_start = Instant::now();
        while settle_start.elapsed() < Duration::from_secs(4) {
            app.drive_terminal_pane();
            std::thread::sleep(Duration::from_millis(50));
        }

        // Simulate app quit: drop every cached fleet session, same as
        // `CoordApp`'s `fleet_terminal_sessions` field dropping at process
        // exit.
        app.fleet_terminal_sessions.clear();

        std::thread::sleep(Duration::from_secs(3));

        let out = std::process::Command::new("ssh")
            .args(["elitebook", "tmux", "list-sessions"])
            .output()
            .expect("ssh list-sessions");
        let stdout = String::from_utf8_lossy(&out.stdout);
        assert!(
            stdout.contains(sess_name),
            "remote tmux session {sess_name} was destroyed after dropping the local \
             session — expected a clean detach:\n{stdout}"
        );

        let _ = std::process::Command::new("ssh")
            .args(["elitebook", "tmux", "kill-session", "-t", sess_name])
            .status();
    }

    // ── #954: create a new terminal on a chosen fleet machine ───────────────

    /// TuiDriver black-box: seed 2 machines, open the Terminal view, press
    /// `n` to open the "new terminal" machine picker, pick the SECOND
    /// machine, accept the default (auto-generated) name, and assert an
    /// optimistic pending node appears directly under the CHOSEN machine —
    /// not the other one — in the left-pane tree. The real create+attach
    /// PTY/tmux/ssh mechanics aren't observable under `TestBackend`, so this
    /// exercises the picker → optimistic-insert path per the issue's
    /// acceptance criteria ("a new node appears under the correct machine…
    /// immediately (optimistic)").
    #[test]
    fn new_terminal_picker_inserts_optimistic_node_under_chosen_machine() {
        use quadraui::tui::testing::driver_with_shell;

        let app = make_test_app(BoardData {
            machines: vec![
                mk_machine("precision", "precision.tail", true, &[]),
                mk_machine("dellserver", "dellserver.tail", true, &[]),
            ],
            ..BoardData::default()
        });

        let mut driver = driver_with_shell(app, CoordApp::shell_config(), 120, 40);
        click_activity_icon(&mut driver, ">");

        // #424: entering the Terminal view defaults to PTY-focused (typed
        // keys go straight to the shell) — F12 releases focus back to the
        // TUI chrome so 'n' reaches the new-terminal keybinding below
        // instead of being typed into the shell.
        driver.press_named(quadraui::NamedKey::F(12));

        driver.type_char('n');
        let screen = driver.screen();
        assert!(
            screen.contains("Select machine for new terminal"),
            "'n' in the Terminal view should open the new-terminal machine \
             picker:\n{screen}",
        );
        assert!(
            screen.contains("dellserver"),
            "the picker should list the second machine:\n{screen}",
        );

        // `fleet_machines_for_terminal` sorts local-first/reachable/name —
        // neither seeded machine is "local" and both are reachable, so the
        // picker lists them alphabetically: "dellserver" (1) before
        // "precision" (2). Pick machine 1 (dellserver).
        driver.type_char('1');
        let screen = driver.screen();
        assert!(
            screen.contains("New terminal on dellserver"),
            "picking a machine should open the optional-name prompt:\n{screen}",
        );

        // Accept the default (auto-generated) name.
        driver.press_named(quadraui::NamedKey::Enter);

        let screen = driver.screen();
        assert!(
            screen.contains("creating"),
            "the optimistic pending terminal should render with its \
             'creating…' marker:\n{screen}",
        );

        // Nesting: the pending row must appear strictly after 'dellserver'
        // (and 'precision', which has no children, must come before it) —
        // i.e. under the chosen machine, not the other one.
        let lines: Vec<&str> = screen.lines().collect();
        let precision_row = lines
            .iter()
            .position(|l| l.contains("precision"))
            .expect("precision row");
        let dellserver_row = lines
            .iter()
            .position(|l| l.contains("dellserver"))
            .expect("dellserver row");
        let pending_row = lines
            .iter()
            .position(|l| l.contains("creating"))
            .expect("pending terminal row");
        assert!(
            precision_row < dellserver_row && dellserver_row < pending_row,
            "the optimistic node must nest directly under 'dellserver' \
             (precision={precision_row}, dellserver={dellserver_row}, \
             pending={pending_row}):\n{screen}",
        );
    }

    /// #954 Gap B/C: the prior test above only asserted the optimistic
    /// node's initial placement — it never drove a discovery sweep to
    /// completion, so the reconciliation/eviction path (and the "main area
    /// hosts a live terminal surface" acceptance bullet) shipped unasserted.
    /// That gap is exactly how the stuck-forever "(creating…)" bug (a real
    /// tmux session existed per `coord terminal list --remote`, but the
    /// tree never reconciled) reached a human smoke test undetected.
    ///
    /// `TuiDriver` offers no way to reach back into a `ShellApp` once it's
    /// wrapped (no `tick()`, no field access through the opaque
    /// `ShellAdapter`), so this drives `CoordApp` methods directly — the
    /// same private-field access `terminal_tree_groups_terminals_under_correct_machine`
    /// above already relies on (`app.fleet_terminals = vec![...]` before
    /// handing the app to `driver_with_shell`) — then re-wraps the app in a
    /// fresh driver afterwards to assert the FINAL state through the normal
    /// black-box screen.
    #[test]
    fn new_terminal_reconciles_after_discovery_sweep_and_hosts_live_terminal() {
        use quadraui::tui::testing::driver_with_shell;

        let mut app = make_test_app(BoardData {
            machines: vec![
                mk_machine("precision", "precision.tail", true, &[]),
                mk_machine("dellserver", "dellserver.tail", true, &[]),
            ],
            ..BoardData::default()
        });

        // Drive the create+attach path directly (equivalent to picking
        // "dellserver" and accepting the default name via the `n` picker —
        // see `create_and_attach_terminal`'s doc comment).
        app.create_and_attach_terminal("dellserver".to_string(), String::new());

        // "the main area hosts a live terminal surface": create_and_attach
        // must have spawned a real PTY session for the new leaf and selected
        // it, so the standalone pane resolves to a live session — not left it
        // to the render-time "Starting shell session…" placeholder.
        //
        // #954 bugs 3/4 (post-#955): the live PTY lives in the leaf's OWN
        // cached `fleet_terminal_sessions[(machine, slug)]` (the #955 model),
        // NOT the bare `terminal_session` scratch shell — `standalone_pty_session()`
        // routes to whichever the selected leaf uses, so it's the model-accurate
        // assertion here (and stays green whichever backing map holds it).
        assert!(
            app.standalone_pty_session().is_some(),
            "create_and_attach_terminal must spawn/attach a live PTY session \
             into the main Terminal pane, not just insert the tree node",
        );
        assert!(
            app.fleet_terminal_sessions
                .contains_key(&("dellserver".to_string(), {
                    app.fleet_terminals
                        .iter()
                        .find(|t| t.pending && t.machine == "dellserver")
                        .map(|t| t.name.clone())
                        .expect("optimistic pending entry")
                })),
            "the live PTY must be cached under the new leaf's (machine, slug) \
             key so the #955 attach path treats it as already-attached (no \
             duplicate/racing second attach — bug 3)",
        );

        let pending_slug = app
            .fleet_terminals
            .iter()
            .find(|t| t.pending && t.machine == "dellserver")
            .map(|t| t.name.clone())
            .expect("create_and_attach_terminal must insert an optimistic pending FleetTerminal");

        // Simulate a landed `coord terminal list --remote` discovery sweep
        // that now covers (machine, slug) as a real, attached session —
        // exactly the state the reviewer's manual repro confirmed via
        // `coord terminal list --remote` (e.g. "elitebook:4f37a8") while the
        // tree stayed stuck on "(creating…)".
        let (tx, rx) = std::sync::mpsc::channel();
        tx.send(vec![FleetTerminal {
            name: pending_slug.clone(),
            machine: "dellserver".to_string(),
            attached: true,
            pending: false,
            pending_sweep_count: 0,
        }])
        .expect("send discovery result");
        app.pending_remote_terminals = Some(rx);

        let changed = app.poll_remote_terminals();
        assert!(changed, "poll_remote_terminals must report a landed sweep");

        // Reconciliation: exactly one entry for (dellserver, slug) survives,
        // it is no longer `pending`, and it carries the real `attached`
        // state from the discovery result — not a duplicate optimistic +
        // real pair, and not evicted outright.
        let matching: Vec<&FleetTerminal> = app
            .fleet_terminals
            .iter()
            .filter(|t| t.machine == "dellserver" && t.name == pending_slug)
            .collect();
        assert_eq!(
            matching.len(),
            1,
            "the optimistic entry must be replaced by exactly one real entry \
             after discovery, not duplicated or dropped: {:?}",
            app.fleet_terminals,
        );
        assert!(
            !matching[0].pending,
            "the reconciled entry must no longer be optimistic/pending: {:?}",
            matching[0],
        );
        assert!(
            matching[0].attached,
            "the reconciled entry must carry the discovery result's \
             `attached` state: {:?}",
            matching[0],
        );

        // Re-render the FINAL state through the normal black-box driver:
        // the tree must show the terminal as attached, and must NOT still
        // show the "(creating…)" marker — the exact symptom the operator
        // reported ("waited 30+ seconds, no change").
        let mut driver = driver_with_shell(app, CoordApp::shell_config(), 120, 40);
        click_activity_icon(&mut driver, ">");
        let screen = driver.screen();
        assert!(
            !screen.contains("creating"),
            "after a discovery sweep confirms the real session, the tree must \
             NOT still show the optimistic '(creating…)' marker:\n{screen}",
        );
        assert!(
            screen.contains(&pending_slug) && screen.contains("attached"),
            "the reconciled terminal must render as attached in the tree:\n{screen}",
        );
        assert!(
            !screen.contains("Starting shell session…") && !screen.contains("Terminal session error"),
            "the main pane must show the live PTY surface, not the \
             no-session placeholder:\n{screen}",
        );
    }

    /// #954 Gap A: the issue requires "a keybinding (e.g. `n`) AND a
    /// context-menu / header '+ New terminal' entry" in the Terminal view —
    /// the `n` keybinding shipped in the original PR, but there was no
    /// visible affordance for an operator who doesn't already know the
    /// shortcut (confirmed missing by the reviewer's manual walkthrough).
    /// Assert the sidebar header button exists, is labelled, and clicking
    /// it opens the same machine picker as `n`.
    #[test]
    fn terminal_view_header_has_new_terminal_button() {
        use quadraui::tui::testing::driver_with_shell;

        let app = make_test_app(BoardData {
            machines: vec![
                mk_machine("precision", "precision.tail", true, &[]),
                mk_machine("dellserver", "dellserver.tail", true, &[]),
            ],
            ..BoardData::default()
        });

        let mut driver = driver_with_shell(app, CoordApp::shell_config(), 120, 40);
        click_activity_icon(&mut driver, ">");

        let screen = driver.screen();
        assert!(
            screen.contains("New terminal"),
            "the Terminal view sidebar header must show a '+ New terminal' \
             affordance, not just the 'n' keybinding:\n{screen}",
        );

        let (x, y) = driver.find("New terminal").unwrap_or_else(|| {
            panic!("'New terminal' header button not found:\n{}", driver.screen())
        });
        driver.click(x, y);

        let screen = driver.screen();
        assert!(
            screen.contains("Select machine for new terminal"),
            "clicking the header button must open the same new-terminal \
             machine picker the 'n' keybinding opens:\n{screen}",
        );
    }

    /// #954 bug 2 (broken Submit button): the name-entry dialog's on-screen
    /// "Submit" button had NO click dispatch in `fire_dialog_button` — only the
    /// Enter key (`events.rs`) created the terminal, so a mouse click on Submit
    /// did nothing. A mouse click on a dialog button routes
    /// `handle_dialog_click` → `fire_dialog_button("submit", …)`; this drives
    /// that dispatch method directly (the button hit-region geometry for a
    /// TextInput dialog is a quadraui rendering detail out of scope here) and
    /// asserts it fires the same create path Enter does.
    #[test]
    fn new_terminal_name_prompt_submit_button_fires_create() {
        let mut app = make_test_app(BoardData {
            machines: vec![mk_machine("precision", "precision.tail", true, &[])],
            ..BoardData::default()
        });
        // Arm the name prompt (equivalent to picking a machine in the picker).
        app.begin_new_terminal_name_prompt("precision".to_string());
        assert!(
            app.pending_new_terminal.is_some(),
            "precondition: the name prompt must be armed",
        );

        // Fire the dialog's "Submit" button exactly as a mouse click on it
        // does. The backend arg is unused by this branch but required by the
        // signature; a headless `TuiBackend` satisfies it.
        let mut backend = quadraui::tui::TuiBackend::new();
        app.fire_dialog_button("submit", &mut backend);

        // The prompt is consumed and an optimistic pending terminal created —
        // the same effect as pressing Enter. Before the fix, "submit" fell
        // through `fire_dialog_button` with no handler and NOTHING happened.
        assert!(
            app.pending_new_terminal.is_none(),
            "clicking Submit must consume the name prompt",
        );
        assert!(
            app.fleet_terminals
                .iter()
                .any(|t| t.pending && t.machine == "precision"),
            "clicking Submit must create the optimistic pending terminal, \
             exactly as pressing Enter does — a Submit click that does nothing \
             is the bug: {:?}",
            app.fleet_terminals,
        );
    }

    /// #954 bug 1 (focus-stealing): entering the Terminal view auto-focuses
    /// the embedded PTY (#424), so every key is normally forwarded to the
    /// shell. When a create-terminal modal is open, though, the modal must own
    /// ALL input — otherwise the focused PTY swallows the number-key selection
    /// and Esc, leaving the picker stuck (the reviewer's manual repro). Open
    /// the picker via the header button (a mouse click, unaffected by PTY
    /// focus), then type '1' WITHOUT releasing focus (no F12) and assert the
    /// key reached the picker (name prompt opens) instead of the shell.
    #[test]
    fn new_terminal_picker_receives_keys_while_pty_focused() {
        use quadraui::tui::testing::driver_with_shell;

        let app = make_test_app(BoardData {
            machines: vec![
                mk_machine("precision", "precision.tail", true, &[]),
                mk_machine("dellserver", "dellserver.tail", true, &[]),
            ],
            ..BoardData::default()
        });

        let mut driver = driver_with_shell(app, CoordApp::shell_config(), 120, 40);
        // Entering the Terminal view sets `terminal_focused = true` (#424) —
        // the PTY is focused, the common case the reviewer hit.
        click_activity_icon(&mut driver, ">");

        // Open the picker via the header button (mouse — reaches the dialog
        // regardless of PTY focus, which is why the operator could OPEN it).
        let (x, y) = driver.find("New terminal").unwrap_or_else(|| {
            panic!("'New terminal' header button not found:\n{}", driver.screen())
        });
        driver.click(x, y);
        assert!(
            driver.screen_contains("Select machine for new terminal"),
            "picker must open:\n{}",
            driver.screen(),
        );

        // Crux of bug 1: type '1' with the PTY still focused (NO F12). The
        // modal must receive it and advance to the name prompt — before the
        // fix this key was swallowed by the focused PTY and the picker stuck.
        driver.type_char('1');
        assert!(
            driver.screen_contains("New terminal on dellserver"),
            "the number-key selection must reach the open picker even while \
             the PTY is focused (bug 1: it was swallowed by the shell):\n{}",
            driver.screen(),
        );
    }

    // ── #956: kill a terminal from the machine tree ──────────────────────────

    /// TuiDriver black-box: seed a discovered terminal, select it, press `K`,
    /// confirm the dialog, and assert the node disappears from the rendered
    /// tree — the acceptance criteria's "optimistic removal". The exact
    /// dispatched argv isn't observable through the `driver_with_shell`
    /// wrapper (it returns an opaque `impl AppLogic` with no field access
    /// back to `CoordApp`), so that's covered separately by the direct-app
    /// unit test `confirm_kill_terminal_dispatches_qualified_target` below —
    /// this test is the rendered-tree half of the acceptance criteria.
    #[test]
    fn kill_terminal_confirm_removes_node_from_tree() {
        use quadraui::tui::testing::driver_with_shell;

        let mut app = make_test_app(BoardData {
            machines: vec![mk_machine("precision", "precision.tail", true, &[])],
            ..BoardData::default()
        });
        app.fleet_terminals = vec![FleetTerminal {
            name: "scratch".to_string(),
            machine: "precision".to_string(),
            attached: false,
            pending: false,
            pending_sweep_count: 0,
        }];

        let mut driver = driver_with_shell(app, CoordApp::shell_config(), 120, 40);
        click_activity_icon(&mut driver, ">");

        // Select the terminal row (not the machine row above it).
        let (x, y) = driver.find("scratch").unwrap_or_else(|| {
            panic!("'scratch' terminal row must be findable:\n{}", driver.screen())
        });
        driver.click(x, y);

        driver.press(Key::Char('K'));
        let screen = driver.screen();
        assert!(
            screen.contains("Kill Terminal") || screen.contains("Kill terminal"),
            "K on a selected terminal row must open the kill-confirm dialog:\n{screen}",
        );
        assert!(
            screen.contains("scratch"),
            "confirm dialog must name the terminal being killed:\n{screen}",
        );

        driver.press(Key::Char('y'));

        // The post-kill toast also names the terminal ("Terminal killed —
        // scratch on precision"), so a whole-screen `contains("scratch")`
        // check would false-negative on the toast text below the tree.
        // Check the TREE specifically: the machine row must lose its
        // terminal-count suffix and no longer have a nested child row.
        let screen = driver.screen();
        let lines: Vec<&str> = screen.lines().collect();
        let precision_row = lines
            .iter()
            .position(|l| l.contains("precision"))
            .expect("precision row");
        assert!(
            !lines[precision_row].contains("(1)"),
            "machine row must lose its terminal count once its only terminal is killed:\n{screen}",
        );
        assert!(
            lines
                .get(precision_row + 1)
                .map(|l| !l.contains("scratch"))
                .unwrap_or(true),
            "killed terminal must no longer render as a nested tree row:\n{screen}",
        );
    }

    /// Cancelling the kill-confirm (any key other than y/Y) must leave the
    /// terminal untouched — node still in the tree.
    #[test]
    fn kill_terminal_cancel_leaves_terminal_untouched() {
        use quadraui::tui::testing::driver_with_shell;

        let mut app = make_test_app(BoardData {
            machines: vec![mk_machine("precision", "precision.tail", true, &[])],
            ..BoardData::default()
        });
        app.fleet_terminals = vec![FleetTerminal {
            name: "scratch".to_string(),
            machine: "precision".to_string(),
            attached: false,
            pending: false,
            pending_sweep_count: 0,
        }];

        let mut driver = driver_with_shell(app, CoordApp::shell_config(), 120, 40);
        click_activity_icon(&mut driver, ">");
        let (x, y) = driver.find("scratch").unwrap_or_else(|| {
            panic!("'scratch' terminal row must be findable:\n{}", driver.screen())
        });
        driver.click(x, y);

        driver.press(Key::Char('K'));
        driver.press(Key::Named(quadraui::NamedKey::Escape));

        let screen = driver.screen();
        assert!(
            screen.contains("scratch"),
            "cancelled kill must leave the terminal in the tree:\n{screen}",
        );
    }

    /// Direct-app unit test (no `TuiDriver` — see the note on
    /// `kill_terminal_confirm_removes_node_from_tree` above for why): select
    /// a REMOTE machine's terminal, confirm the kill, and assert the exact
    /// `["terminal", "kill", "<machine>:<name>"]` argv reached the no-spawn
    /// `CommandRunner` seam — the acceptance criteria's "assert the kill
    /// command is issued for the right machine:name". `coord terminal kill`
    /// itself (#952) resolves local-vs-remote/ssh routing from
    /// `coordinator.yml`, so the TUI dispatches the identical qualified
    /// target regardless of which machine owns the terminal.
    #[test]
    fn confirm_kill_terminal_dispatches_qualified_target() {
        let mut app = make_test_app(BoardData {
            machines: vec![mk_machine("dellserver", "dellserver.tail", true, &[])],
            ..BoardData::default()
        });
        app.fleet_terminals = vec![FleetTerminal {
            name: "build".to_string(),
            machine: "dellserver".to_string(),
            attached: false,
            pending: false,
            pending_sweep_count: 0,
        }];
        app.active_view = SidebarView::Terminal;
        app.terminal_tree_selected = Some(vec![0, 0]);

        assert!(
            app.open_kill_terminal_confirm(),
            "a selected terminal row must arm the confirm"
        );
        let pending = app
            .pending_kill_terminal
            .clone()
            .expect("pending_kill_terminal must be set");
        assert_eq!(pending.machine, "dellserver");
        assert_eq!(pending.name, "build");

        app.confirm_kill_terminal(pending);

        assert_eq!(
            app.command_runner.spawned_calls,
            vec![vec![
                "terminal".to_string(),
                "kill".to_string(),
                "dellserver:build".to_string(),
            ]],
            "must dispatch `coord terminal kill dellserver:build`; got {:?}",
            app.command_runner.spawned_calls,
        );
        assert!(
            app.fleet_terminals.is_empty(),
            "killed terminal must be removed from fleet_terminals optimistically"
        );
    }

    /// `K` / the context-menu item on a MACHINE row (not a terminal row) must
    /// be a no-op — kill only applies to terminal rows.
