        click_activity_icon(&mut driver, "§");
        driver.render();

        let (_, newest_y) = driver.find("NEWEST_MARKER").unwrap_or_else(|| {
            panic!("NEWEST_MARKER row not rendered:\n{}", driver.screen())
        });
